// src/tools/internal/getForumData.ts
async function getPriorTurns(topicId, sessionId, opts = {}) {
  const session = dbGetForumSession(topicId, sessionId);
  if (!session)
    return [];
  const allTurns = session.rounds.flatMap((r2) => r2.turns);
  return allTurns.filter((t2) => {
    if (opts.round !== undefined && t2.round !== opts.round)
      return false;
    if (opts.party_id !== undefined && t2.representative_id !== `rep-${opts.party_id}`)
      return false;
    return true;
  });
}
async function getForumSession(topicId, sessionId) {
  const session = dbGetForumSession(topicId, sessionId);
  if (!session)
    throw new Error(`Forum session not found: ${sessionId}`);
  return session;
}
async function writeForumSession(topicId, session) {
  dbUpsertForumSession(topicId, session);
}

