import { join as join5 } from "path";
import { mkdir } from "fs/promises";
function getDataDir3() {
  return process.env.DATA_DIR || "/home/nima/dana/data";
}
function artifactPath(topicId, runId, name) {
  return join5(getDataDir3(), "topics", topicId, "logs", `run-${runId}`, `${name}.json`);
}
async function writeArtifact(topicId, runId, name, data2) {
  const dir = join5(getDataDir3(), "topics", topicId, "logs", `run-${runId}`);
  await mkdir(dir, { recursive: true });
  const path = artifactPath(topicId, runId, name);
  const written_at = new Date().toISOString();
  await Bun.write(path, JSON.stringify(data2, null, 2));
  return { path, written_at };
}

// src/agents/DiscoveryResearcher.ts
init_promptLoader();
init_agenticLoop();
init_settings();
init_tokenBudget();
init_stream2();
