async function runDiscoveryResearcher(topicId, title, description, model, orientation) {
  const today = new Date().toISOString().slice(0, 10);
  const year = new Date().getFullYear().toString();
  log.discovery(`DiscoveryResearcher: starting agentic research for "${title}"`);
  emitThink(topicId, "\uD83D\uDD2C", "Agentic research started", `${orientation.angles.length} angles, ${orientation.seed_queries.length} seed queries`);
  const config = await resolvePrompt("discovery/agentic-research", {
    today,
    year,
    title,
    description,
    angles: orientation.angles.map((a12, i) => `${i + 1}. ${a12}`).join(`
`),
    party_types: orientation.likely_party_types.join(", "),
    seed_queries: orientation.seed_queries.map((q, i) => `${i + 1}. ${q}`).join(`
`)
  });
  const effectiveModel = config.model ?? model;
  const userMessage = `Begin your research. Start with the seed queries, then go deeper based on what you find. Output your final results as JSON when done.`;
  const controls = dbGetControls();
  const raw = await runAgenticLoop({
    model: effectiveModel,
    topicId,
    stage: "discovery",
    tools: config.tools,
    maxIterations: controls.discovery_research_iterations,
    temperature: 0.3,
    max_tokens: budgetOutput(effectiveModel, config.content + userMessage, { min: 8000, max: 16000 }),
    contextWarningThreshold: controls.discovery_context_warning,
    messages: [
      { role: "system", content: config.content },
      { role: "user", content: userMessage }
    ]
  });
  const match = raw.match(/\{[\s\S]+\}/);
  if (!match) {
    log.discovery("DiscoveryResearcher: failed to parse JSON from output");
    throw new Error("Failed to parse research output JSON");
  }
  const result = JSON.parse(match[0]);
  const parties = (result.parties ?? []).map((p) => ({
    ...p,
    id: p.id || p.name.toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_|_$/g, "").slice(0, 30),
    auto_discovered: true,
    user_verified: false
  }));
  log.discovery(`DiscoveryResearcher: found ${parties.length} parties, ${(result.sources ?? []).length} sources`);
  emitThink(topicId, "\u2705", "Research complete", `${parties.length} parties identified from ${(result.sources ?? []).length} sources`);
  for (const p of parties) {
    emitThink(topicId, "\uD83E\uDDE9", `Party: ${p.name}`, `${p.type.replace(/_/g, " ")} \xB7 weight ${p.weight}`);
    await new Promise((r2) => setTimeout(r2, 150));
  }
  return { parties, sources: result.sources ?? [] };
}

// src/agents/PartyScorer.ts
init_promptLoader();
init_agenticLoop();
init_settings();
init_tokenBudget();
init_stream2();
init_logger();
var AXIS_KEYS = [
  "military_capacity",
  "economic_control",
  "information_control",
  "international_support",
  "internal_legitimacy"
];
function computePentagonScore(factors) {
  const s = AXIS_KEYS.map((k2) => Math.max(0, Math.min(100, factors[k2] ?? 0)));
  const sin72 = Math.sin(2 * Math.PI / 5);
  let area = 0;
  for (let i = 0;i < 5; i++) {
    area += s[i] * s[(i + 1) % 5];
  }
  area *= 0.5 * sin72;
  const maxArea = 0.5 * sin72 * 5 * 100 * 100;
  return Math.round(100 * area / maxArea);
}
async function scoreOneParty(topicId, title, description, party, model) {
  const today = new Date().toISOString().slice(0, 10);
  const year = new Date().getFullYear().toString();
  const partyProfile = JSON.stringify({
    id: party.id,
    name: party.name,
    type: party.type,
    description: party.description,
    agenda: party.agenda,
    means: party.means,
    circle: party.circle
  }, null, 2);
  const config = await resolvePrompt("discovery/score-axes", {
    today,
    year,
    topic: title,
    description,
    party_profile: partyProfile
  });
  const effectiveModel = config.model ?? model;
  log.discovery(`PartyScorer: scoring "${party.name}" with ${effectiveModel}`);
  emitThink(topicId, "\uD83D\uDCCA", `Scoring: ${party.name}`, "Researching 5 power axes\u2026");
  const controls = dbGetControls();
  const raw = await runAgenticLoop({
    model: effectiveModel,
    topicId,
    stage: "scoring",
    tools: config.tools,
    maxIterations: controls.scoring_iterations,
    temperature: 0.2,
    max_tokens: budgetOutput(effectiveModel, config.content, { min: 2000, max: 4000 }),
    contextWarningThreshold: controls.scoring_context_warning,
    messages: [
      { role: "system", content: config.content },
      { role: "user", content: `Begin your research on ${party.name}. Search for specific metrics and data for each of the 5 dimensions. Output your scores as JSON when done.` }
    ]
  });
  const match = raw.match(/\{[\s\S]+\}/);
  if (!match)
    throw new Error(`PartyScorer: failed to parse output for ${party.name}`);
  const parsed = JSON.parse(match[0]);
  const scores = parsed.scores;
  const factors = {
    military_capacity: 0,
    economic_control: 0,
    information_control: 0,
    international_support: 0,
    internal_legitimacy: 0
  };
  const evidence = {};
  for (const key2 of AXIS_KEYS) {
    const entry = scores[key2];
    if (entry) {
      factors[key2] = Math.max(0, Math.min(100, Math.round(entry.score)));
      evidence[key2] = entry.evidence ?? "";
    }
  }
  const overall = computePentagonScore(factors);
  log.discovery(`PartyScorer: ${party.name} \u2192 overall=${overall} [${AXIS_KEYS.map((k2) => `${k2.slice(0, 3)}=${factors[k2]}`).join(", ")}]`);
  emitThink(topicId, "\u2705", `Scored: ${party.name}`, `Overall ${overall} \xB7 mil=${factors.military_capacity} eco=${factors.economic_control} info=${factors.information_control} intl=${factors.international_support} legit=${factors.internal_legitimacy}`);
  return { factors, evidence, overall };
}
async function scoreAllParties(topicId, title, description, parties, model) {
  log.discovery(`PartyScorer: scoring ${parties.length} parties`);
  emitThink(topicId, "\uD83D\uDCCA", "Scoring party power axes", `${parties.length} parties \xD7 5 axes with evidence`);
  const controls = dbGetControls();
  const BATCH = controls.scoring_batch_size;
  for (let i = 0;i < parties.length; i += BATCH) {
    const batch = parties.slice(i, i + BATCH);
    emitThink(topicId, "\uD83D\uDCCA", `Scoring batch ${Math.floor(i / BATCH) + 1}`, batch.map((p) => p.name).join(", "));
    const results = await Promise.all(batch.map(async (party) => {
      try {
        return await scoreOneParty(topicId, title, description, party, model);
      } catch (e) {
        log.error("DISCOVERY", `PartyScorer failed for ${party.name}: ${e}`);
        emitThink(topicId, "\u26A0", `Scoring failed: ${party.name}`, String(e));
        return null;
      }
    }));
    for (let j = 0;j < batch.length; j++) {
      const result = results[j];
      if (result) {
        batch[j].weight_factors = result.factors;
        batch[j].weight = result.overall;
        batch[j].weight_evidence = result.evidence;
      }
    }
  }
  log.discovery(`PartyScorer: complete. Scores: ${parties.map((p) => `${p.name}=${p.weight}`).join(", ")}`);
  return parties;
}

// src/agents/DiscoveryAgent.ts
async function parseWithRetry(call, parse10, validate, maxAttempts = 3) {
  let lastError = "";
  for (let i = 0;i < maxAttempts; i++) {
    const hint = i > 0 ? `Previous attempt failed: ${lastError}. Output ONLY valid JSON. No trailing commas. No markdown fences.` : undefined;
    const raw = await call(hint);
    try {
      const v = parse10(raw);
      if (!validate(v))
        throw new Error("Validation failed");
      return v;
    } catch (e) {
      lastError = String(e);
      log.discovery(`parseWithRetry attempt ${i + 1} failed: ${lastError}`);
    }
  }
  throw new Error(`Failed after ${maxAttempts} attempts: ${lastError}`);
}
function slugify3(name) {
  return name.toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_|_$/g, "").slice(0, 30);
}
function todayStr() {
  return new Date().toISOString().slice(0, 10);
}
function currentYear() {
  return new Date().getFullYear().toString();
}
async function runDiscoveryAgent(topicId, title, description, model, runId, onProgress) {
  const today = todayStr();
  const year = currentYear();
  log.discovery(`Starting discovery for "${title}" on ${today}`);
  emitThink(topicId, "\uD83D\uDCC5", `Today is ${today}`, "Orienting research\u2026");
  onProgress?.(`Discovery: orienting for "${title}"`);
  const orientConfig = await resolvePrompt("discovery/orient", { today, year });
  const effectiveOrientModel = orientConfig.model ?? model;
  const orientInput = `TOPIC: ${title}

DESCRIPTION: ${description}`;
  emitThink(topicId, "\uD83E\uDDE0", "Analyzing topic angles", "Economic \xB7 Geopolitical \xB7 Military \xB7 Adversarial\u2026");
  const orientBudget = budgetOutput(effectiveOrientModel, orientConfig.content + orientInput, { min: 800, max: 2000 });
  const orientation = await parseWithRetry(async (hint) => {
    if (orientConfig.tools.length > 0) {
      return runAgenticLoop({
        model: effectiveOrientModel,
        topicId,
        stage: "discovery",
        tools: orientConfig.tools,
        messages: [
          { role: "system", content: orientConfig.content },
          { role: "user", content: orientInput + (hint ? `

${hint}` : "") }
        ],
        temperature: 0.3,
        max_tokens: orientBudget
      });
    } else {
      return chatCompletionText({
        model: effectiveOrientModel,
        messages: [
          { role: "system", content: orientConfig.content },
          { role: "user", content: orientInput + (hint ? `

${hint}` : "") }
        ],
        temperature: 0.3,
        max_tokens: orientBudget
      });
    }
  }, (raw) => {
    const match = raw.match(/\{[\s\S]+\}/);
    if (!match)
      throw new Error("No JSON object found");
    return JSON.parse(match[0]);
  }, (v) => Array.isArray(v.seed_queries) && v.seed_queries.length >= 3);
  log.discovery(`Orientation: ${orientation.angles.length} angles, ${orientation.seed_queries.length} queries`);
  emitThink(topicId, "\uD83D\uDDFA\uFE0F", `${orientation.angles.length} angles identified`, orientation.angles.slice(0, 3).join(" \xB7 "));
  onProgress?.("Discovery: agentic research in progress\u2026");
  const researchResult = await runDiscoveryResearcher(topicId, title, description, model, orientation);
  let parties = researchResult.parties;
  onProgress?.("Discovery: refining party list\u2026");
  emitThink(topicId, "\uD83D\uDD00", "Refining party list", "Checking for merges, deletions, and new actors\u2026");
  try {
    const partyListSummary = parties.map((p) => `${p.id} | ${p.name} (${p.type}) \u2014 ${p.agenda.slice(0, 120)}`).join(`
`);
    const sourceSummary = researchResult.sources.slice(0, 40).map((s) => `[${s.url}] ${s.title}: ${s.used_for}`).join(`
`);
    const refineConfig = await resolvePrompt("discovery/refine-parties", {
      today,
      topic: title,
      party_list: partyListSummary,
      research_summary: sourceSummary
    });
    const effectiveRefineModel = refineConfig.model ?? model;
    const refineBudget = budgetOutput(effectiveRefineModel, refineConfig.content, { min: 500, max: 1500 });
    const refineUserMsg = "Analyze the party list against the research findings and output your consolidation decisions.";
    let refineRaw;
    if (refineConfig.tools.length > 0) {
      refineRaw = await runAgenticLoop({
        model: effectiveRefineModel,
        topicId,
        stage: "discovery",
        tools: refineConfig.tools,
        messages: [
          { role: "system", content: refineConfig.content },
          { role: "user", content: refineUserMsg }
        ],
        temperature: 0.2,
        max_tokens: refineBudget
      });
    } else {
      refineRaw = await chatCompletionText({
        model: effectiveRefineModel,
        messages: [
          { role: "system", content: refineConfig.content },
          { role: "user", content: refineUserMsg }
        ],
        temperature: 0.2,
        max_tokens: refineBudget
      });
    }
    const refineMatch = refineRaw.match(/\{[\s\S]+\}/);
    if (refineMatch) {
      const decisions = JSON.parse(refineMatch[0]);
      for (const del of decisions.delete ?? []) {
        const idx = parties.findIndex((p) => p.id === del.id);
        if (idx !== -1) {
          emitThink(topicId, "\uD83D\uDDD1\uFE0F", `Removing \xB7 ${parties[idx].name}`, del.reason);
          log.discovery(`Removing party "${parties[idx].name}": ${del.reason}`);
          parties.splice(idx, 1);
        }
      }
      for (const merge2 of decisions.merge ?? []) {
        const sources = merge2.source_ids.map((id) => parties.find((p) => p.id === id)).filter(Boolean);
        if (sources.length < 2)
          continue;
        const merged = {
          id: slugify3(merge2.into),
          name: merge2.into,
          type: sources[0].type,
          description: sources.map((s) => s.description).join(" "),
          weight: Math.round(sources.reduce((s, p) => s + p.weight, 0) / sources.length),
          weight_factors: sources[0].weight_factors,
          agenda: sources.map((s) => s.agenda).filter(Boolean).join("; "),
          means: [...new Set(sources.flatMap((s) => s.means))],
          circle: {
            visible: [...new Set(sources.flatMap((s) => s.circle?.visible ?? []))],
            shadow: [...new Set(sources.flatMap((s) => s.circle?.shadow ?? []))]
          },
          stance: sources[0].stance,
          vulnerabilities: [...new Set(sources.flatMap((s) => s.vulnerabilities))],
          auto_discovered: true,
          user_verified: false
        };
        for (const src of sources) {
          const idx = parties.findIndex((p) => p.id === src.id);
          if (idx !== -1)
            parties.splice(idx, 1);
        }
        parties.push(merged);
        emitThink(topicId, "\uD83D\uDD00", `Merging \xB7 ${sources.map((s) => s.name).join(" + ")} \u2192 ${merge2.into}`, merge2.reason);
        log.discovery(`Merged \u2192 "${merge2.into}": ${merge2.reason}`);
      }
      for (const add3 of decisions.add ?? []) {
        if (parties.find((p) => p.name.toLowerCase() === add3.name.toLowerCase()))
          continue;
        const stub = {
          id: slugify3(add3.name),
          name: add3.name,
          type: add3.type ?? "non_state",
          description: add3.reason,
          weight: 30,
          weight_factors: { military_capacity: 0, economic_control: 0, information_control: 0, international_support: 0, internal_legitimacy: 0 },
          agenda: add3.reason,
          means: [],
          circle: { visible: [], shadow: [] },
          stance: "active",
          vulnerabilities: [],
          auto_discovered: true,
          user_verified: false
        };
        parties.push(stub);
        emitThink(topicId, "\u2795", `Adding \xB7 ${add3.name}`, add3.reason);
        log.discovery(`Added party "${add3.name}": ${add3.reason}`);
      }
      for (const group of decisions.group ?? []) {
        const keepSeparate = new Set(group.keep_separate ?? []);
        const sources = group.source_ids.filter((id) => !keepSeparate.has(id)).map((id) => parties.find((p) => p.id === id)).filter(Boolean);
        if (sources.length < 2)
          continue;
        const alliance = {
          id: slugify3(group.alliance_name),
          name: group.alliance_name,
          type: "alliance",
          description: `Alliance of ${sources.map((s) => s.name).join(", ")}. ${group.reason}`,
          weight: 0,
          weight_factors: { military_capacity: 0, economic_control: 0, information_control: 0, international_support: 0, internal_legitimacy: 0 },
          agenda: [...new Set(sources.map((s) => s.agenda).filter(Boolean))].join("; "),
          means: [...new Set(sources.flatMap((s) => s.means))],
          circle: {
            visible: sources.map((s) => s.name),
            shadow: [...new Set(sources.flatMap((s) => s.circle?.shadow ?? []))]
          },
          stance: sources[0].stance,
          vulnerabilities: [...new Set(sources.flatMap((s) => s.vulnerabilities))],
          auto_discovered: true,
          user_verified: false
        };
        for (const src of sources) {
          const idx = parties.findIndex((p) => p.id === src.id);
          if (idx !== -1)
            parties.splice(idx, 1);
        }
        parties.push(alliance);
        emitThink(topicId, "\uD83E\uDD1D", `Alliance \xB7 ${sources.map((s) => s.name).join(" + ")} \u2192 ${group.alliance_name}`, group.reason);
        log.discovery(`Grouped \u2192 "${group.alliance_name}": ${group.reason}`);
      }
      log.discovery(`Refinement complete: ${parties.length} parties`);
    }
  } catch (e) {
    log.discovery(`Party refinement failed (non-fatal): ${e}`);
  }
  onProgress?.("Discovery: scoring party power axes\u2026");
  emitThink(topicId, "\uD83D\uDCCA", "Scoring party power", `${parties.length} parties \xD7 5 axes with evidence`);
  try {
    parties = await scoreAllParties(topicId, title, description, parties, model);
  } catch (e) {
    log.error("DISCOVERY", "Party scoring failed (non-fatal), keeping preliminary scores", e);
  }
  emitThink(topicId, "\uD83D\uDCBE", `Saving ${parties.length} parties`, `${researchResult.sources.length} sources collected`);
  log.discovery(`Saving ${parties.length} parties to DB`);
  dbSetParties(topicId, parties);
  onProgress?.(`Discovery: complete \u2014 ${parties.length} parties identified`);
  const output = {
    topic_id: topicId,
    parties,
    research_findings: researchResult.sources,
    search_queries: orientation.seed_queries,
    run_id: runId
  };
  await writeArtifact(topicId, runId, "discovery_output", output);
  return output;
}

