// src/tools/processing/storeClue.ts
init_clues();
function domainOf(url) {
  try {
    return new URL(url).hostname.replace(/^www\./, "");
  } catch {
    return url;
  }
}
async function storeClue(input) {
  const timelineDate = input.timelineDate || input.processed.date_references[0] || new Date().toISOString().slice(0, 10);
  const primaryUrl = input.sourceUrls[0] ?? "";
  const existingId = dbClueExists(input.topicId, primaryUrl, timelineDate);
  if (existingId) {
    return { clue_id: existingId, version: 1, status: "duplicate" };
  }
  const id = dbNextClueId(input.topicId);
  const now = new Date().toISOString();
  const outlets = input.sourceOutlets?.length ? input.sourceOutlets : input.sourceUrls.map((u) => domainOf(u));
  const originSources = input.sourceUrls.map((url, i) => ({
    url,
    outlet: outlets[i] ?? domainOf(url),
    is_republication: false
  }));
  const version = {
    v: 1,
    date: now,
    title: input.title,
    raw_source: {
      urls: input.sourceUrls,
      outlets,
      fetched_at: input.fetchedAt
    },
    source_credibility: {
      score: input.processed.source_credibility_score,
      notes: input.processed.credibility_notes,
      bias_flags: input.processed.bias_flags,
      origin_sources: originSources
    },
    bias_corrected_summary: input.processed.bias_corrected_summary,
    relevance_score: input.processed.relevance_score,
    party_relevance: input.partyRelevance || [],
    domain_tags: input.domainTags || [],
    timeline_date: timelineDate,
    clue_type: input.clueType || "event",
    change_note: input.changeNote || "Initial version",
    key_points: input.processed.key_points
  };
  dbInsertClue(input.topicId, {
    id,
    current: 1,
    added_at: now,
    last_updated_at: now,
    added_by: input.addedBy || "auto",
    status: input.initialStatus ?? "pending",
    version
  });
  return { clue_id: id, version: 1, status: "created" };
}

// src/agents/PartyEnrichmentAgent.ts
init_researchCorpus();
init_stream2();
init_logger();
function domainOf2(url) {
  try {
    return new URL(url).hostname.replace(/^www\./, "");
  } catch {
    return url;
  }
}
async function runPartyEnrichmentAgent(topicId, title, description, party, existingClues, model) {
  const today = new Date().toISOString().slice(0, 10);
  const year = new Date().getFullYear().toString();
  const currentMonth = new Date().toLocaleString("en-US", { month: "long", year: "numeric" });
  log.enrichment(`PartyEnrichmentAgent: starting for "${party.name}"`);
  emitThink(topicId, "\uD83D\uDD2C", `Enriching: ${party.name}`, `${existingClues.length} existing clues`);
  const partyProfile = JSON.stringify({
    id: party.id,
    name: party.name,
    type: party.type,
    description: party.description,
    weight: party.weight,
    agenda: party.agenda,
    means: party.means,
    circle: party.circle,
    stance: party.stance,
    vulnerabilities: party.vulnerabilities
  }, null, 2);
  const existingCluesSummary = existingClues.length > 0 ? existingClues.map((c) => `- [${c.id}] (${c.clue_type}, cred=${c.credibility}) ${c.title}: ${c.summary.slice(0, 150)}`).join(`
`) : "No existing clues for this party.";
  const controls = dbGetControls();
  const config = await resolvePrompt("enrichment/agentic-enrich", {
    today,
    year,
    current_month: currentMonth,
    title,
    description,
    party_profile: partyProfile,
    existing_clues: existingCluesSummary,
    max_searches: String(controls.enrichment_max_searches_per_round),
    max_fetches: String(controls.enrichment_max_fetches_per_round)
  });
  const effectiveModel = config.model ?? model;
  const storeClueToolDef = TOOL_REGISTRY["store_clue"];
  const effectiveTools = [...config.tools, ...storeClueToolDef && !config.tools.some((t2) => t2.function.name === "store_clue") ? [storeClueToolDef] : []];
  const storedClueIds = [];
  const storeClueHandler = async (args) => {
    try {
      const sourceUrls = args.source_urls ?? [];
      const sourceOutlets = args.source_outlets ?? sourceUrls.map((u) => domainOf2(u));
      const result = await storeClue({
        topicId,
        title: String(args.title ?? ""),
        sourceUrls,
        sourceOutlets,
        fetchedAt: new Date().toISOString(),
        processed: {
          extracted_content: "",
          bias_corrected_summary: String(args.summary ?? ""),
          bias_flags: args.bias_flags ?? [],
          source_credibility_score: Number(args.credibility ?? 50),
          credibility_notes: `Sources: ${sourceOutlets.join(", ")}`,
          origin_sources: sourceUrls.map((url, i) => ({
            url,
            outlet: sourceOutlets[i] ?? domainOf2(url),
            is_republication: false
          })),
          key_points: args.key_points ?? [],
          date_references: [String(args.date ?? today)],
          relevance_score: Number(args.relevance ?? 50)
        },
        partyRelevance: args.parties ?? [party.id],
        domainTags: args.domain_tags ?? [],
        timelineDate: String(args.date ?? today),
        clueType: String(args.clue_type ?? "fact"),
        addedBy: "auto",
        changeNote: `Enrichment agent: ${party.name}`,
        initialStatus: "pending"
      });
      if (result.status === "created") {
        storedClueIds.push(result.clue_id);
        emitThink(topicId, "\uD83D\uDCCC", `Clue stored: ${String(args.title ?? "").slice(0, 50)}`, `${result.clue_id} \xB7 cred=${args.credibility}`);
        log.enrichment(`  Clue stored: ${result.clue_id} "${String(args.title ?? "").slice(0, 50)}"`);
        try {
          const { runFactCheck: runFactCheck2 } = await Promise.resolve().then(() => (init_FactCheckAgent(), exports_FactCheckAgent));
          const verdict = await runFactCheck2({
            topicId,
            clueId: result.clue_id,
            title: String(args.title ?? ""),
            summary: String(args.summary ?? ""),
            sourceUrls,
            sourceOutlets,
            keyPoints: args.key_points ?? [],
            biasFlags: args.bias_flags ?? [],
            credibility: Number(args.credibility ?? 50),
            partyContext: party.name,
            topicTitle: title,
            topicDescription: description,
            model: effectiveModel
          });
          log.enrichment(`  Fact-check: ${verdict.verdict} for "${String(args.title ?? "").slice(0, 40)}"`);
          emitThink(topicId, verdict.verdict === "verified" ? "\u2705" : verdict.verdict === "disputed" ? "\uD83D\uDD36" : "\u26A0\uFE0F", `${verdict.verdict.toUpperCase()}: ${String(args.title ?? "").slice(0, 50)}`, verdict.bias_analysis.slice(0, 100));
          return JSON.stringify({ status: "created", clue_id: result.clue_id, fact_check: verdict.verdict, bias: verdict.bias_analysis.slice(0, 200) });
        } catch (fcErr) {
          log.enrichment(`  Fact-check failed for ${result.clue_id}: ${fcErr}`);
          return JSON.stringify({ status: "created", clue_id: result.clue_id, fact_check: "skipped" });
        }
      } else {
        log.enrichment(`  Duplicate clue skipped: ${result.clue_id}`);
        return JSON.stringify({ status: "duplicate", clue_id: result.clue_id, message: "This clue already exists" });
      }
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      log.enrichment(`  store_clue failed: ${msg}`);
      return JSON.stringify({ error: msg });
    }
  };
  let corpusContext = "";
  try {
    const corpusPages = getPagesForParty(topicId, party.name, 10);
    if (corpusPages.length > 0) {
      const previews = corpusPages.map((p) => `- [${p.title}](${p.url}): ${p.content.slice(0, 200).replace(/\n/g, " ")}...`);
      corpusContext = `

EXISTING RESEARCH CORPUS (${corpusPages.length} pages from earlier stages \u2014 use these to avoid redundant searches):
${previews.join(`
`)}`;
      log.enrichment(`  Corpus: injected ${corpusPages.length} pages as context for ${party.name}`);
    }
  } catch {}
  const raw = await runAgenticLoop({
    model: effectiveModel,
    topicId,
    stage: "enrichment",
    tools: effectiveTools,
    maxIterations: controls.enrichment_iterations,
    temperature: 0.2,
    max_tokens: budgetOutput(effectiveModel, config.content, { min: 3000, max: 6000 }),
    contextWarningThreshold: controls.enrichment_context_warning,
    customTools: { store_clue: storeClueHandler },
    freeTools: ["store_clue"],
    perRoundCaps: {
      web_search: controls.enrichment_max_searches_per_round,
      fetch_url: controls.enrichment_max_fetches_per_round
    },
    messages: [
      { role: "system", content: config.content },
      { role: "user", content: `Begin your research on ${party.name}. Use the tools to search, fetch, and store clues. Each clue will be independently fact-checked. Output your final profile update as JSON when done.${corpusContext}` }
    ]
  });
  let profileUpdate = null;
  try {
    const match = raw.match(/\{[\s\S]+\}/);
    if (match) {
      const parsed = JSON.parse(match[0]);
      profileUpdate = parsed.profile_update ?? null;
    }
  } catch (e) {
    log.enrichment(`PartyEnrichmentAgent: failed to parse final output for ${party.name}: ${e}`);
  }
  log.enrichment(`PartyEnrichmentAgent: ${party.name} complete \u2014 ${storedClueIds.length} clues stored`);
  emitThink(topicId, "\u2705", `Enrichment complete: ${party.name}`, `${storedClueIds.length} clues stored`);
  return {
    partyId: party.id,
    storedClueIds,
    profileUpdate
  };
}

// src/agents/EnrichmentAgent.ts
async function runEnrichmentAgent(topicId, title, description, models, runId, onProgress) {
  log.separator();
  log.enrichment(`Starting enrichment for "${title}"`);
  log.enrichment(`Model: ${models.enrichment}`);
  log.separator();
  const parties = dbGetParties(topicId);
  const allClueIds = [];
  const enrichedPartyIds = [];
  const factCheckTotals = { verified: 0, disputed: 0, misleading: 0, skipped: 0 };
  emit(topicId, { type: "progress", stage: "enrichment", pct: 0.05, msg: `Enriching ${parties.length} parties with agentic research\u2026` });
  const controls = dbGetControls();
  const BATCH = controls.enrichment_batch_size;
  for (let i = 0;i < parties.length; i += BATCH) {
    const batch = parties.slice(i, i + BATCH);
    const pct = 0.1 + i / parties.length * 0.8;
    emit(topicId, { type: "progress", stage: "enrichment", pct, msg: `Researching: ${batch.map((p) => p.name).join(", ")}` });
    onProgress?.(`Enriching: ${batch.map((p) => p.name).join(", ")}`);
    const results = await Promise.all(batch.map(async (party) => {
      const existingClues = getExistingCluesForParty(topicId, party.id);
      return runPartyEnrichmentAgent(topicId, title, description, party, existingClues, models.enrichment);
    }));
    for (const result of results) {
      allClueIds.push(...result.storedClueIds);
      if (result.profileUpdate) {
        const party = parties.find((p) => p.id === result.partyId);
        if (party) {
          Object.assign(party, result.profileUpdate);
          enrichedPartyIds.push(result.partyId);
          log.enrichment(`Profile updated: ${party.name}`);
        }
      }
    }
  }
  dbSetParties(topicId, parties);
  const allClues = dbGetClues(topicId);
  for (const c of allClues) {
    const cur = c.versions.find((v2) => v2.v === c.current);
    if (!cur?.fact_check) {
      factCheckTotals.skipped++;
      continue;
    }
    const v = cur.fact_check.verdict;
    if (v === "verified")
      factCheckTotals.verified++;
    else if (v === "disputed")
      factCheckTotals.disputed++;
    else if (v === "misleading")
      factCheckTotals.misleading++;
    else
      factCheckTotals.skipped++;
  }
  const totalCluesAfter = dbCountClues(topicId);
  emit(topicId, { type: "progress", stage: "enrichment", pct: 1, msg: "Enrichment complete" });
  onProgress?.(`Enrichment complete: ${allClueIds.length} clues, ${enrichedPartyIds.length} profiles updated`);
  log.separator();
  log.enrichment(`Enrichment COMPLETE: ${allClueIds.length} clues stored, ${enrichedPartyIds.length} profiles enriched, ${totalCluesAfter} total in DB`);
  log.separator();
  const output = {
    topic_id: topicId,
    run_id: runId,
    enriched_party_ids: enrichedPartyIds,
    clue_ids: allClueIds,
    fact_check: factCheckTotals,
    total_clues_after: totalCluesAfter
  };
  await writeArtifact(topicId, runId, "enrichment_output", output);
  return output;
}
function getExistingCluesForParty(topicId, partyId) {
  const allClues = dbGetClues(topicId);
  return allClues.filter((clue) => {
    const cur = clue.versions.find((v) => v.v === clue.current);
    return cur?.party_relevance?.includes(partyId);
  }).map((clue) => {
    const cur = clue.versions.find((v) => v.v === clue.current);
    return {
      id: clue.id,
      title: cur.title,
      summary: cur.bias_corrected_summary,
      credibility: cur.source_credibility.score,
      clue_type: cur.clue_type
    };
  });
}

// src/agents/WeightCalculator.ts
init_proxyClient();
init_agenticLoop();
init_settings();
init_promptLoader();
init_stream2();
init_logger();
init_parties();
var LOW_WEIGHT_THRESHOLD = 15;
function computeSpeakingBudget(weight, totalWeight, isLowWeight) {
  const controls = dbGetControls();
  const ROUND_POOLS = { opening: controls.forum_speaking_budget, rebuttal: Math.round(controls.forum_speaking_budget * 0.67), closing: Math.round(controls.forum_speaking_budget * 0.5) };
  const MIN_FLOOR = 150;
  if (isLowWeight) {
    return { opening_statement: MIN_FLOOR, rebuttal: MIN_FLOOR, closing: MIN_FLOOR, minimum_floor: MIN_FLOOR };
  }
  const ratio = weight / totalWeight;
  return {
    opening_statement: Math.max(MIN_FLOOR, Math.round(ratio * ROUND_POOLS.opening)),
    rebuttal: Math.max(MIN_FLOOR, Math.round(ratio * ROUND_POOLS.rebuttal)),
    closing: Math.max(MIN_FLOOR, Math.round(ratio * ROUND_POOLS.closing)),
    minimum_floor: MIN_FLOOR
  };
}
async function runForumPrep(topicId, title, model, runId, onProgress) {
  const personaConfig = await resolvePrompt("weight/persona-generation");
  const personaModel = personaConfig.model ?? model;
  const parties = dbGetParties(topicId);
  const totalWeight = parties.reduce((sum, p) => sum + (p.weight ?? 0), 0);
  log.weight(`Forum prep: generating personas for ${parties.length} parties (total weight ${totalWeight})`);
  onProgress?.(`Forum prep: generating ${parties.length} representative personas`);
  emitThink(topicId, "\uD83C\uDFAD", "Generating forum representatives", `${parties.length} parties`);
  const representatives = [];
  const PERSONA_BATCH = 4;
  for (let bi = 0;bi < parties.length; bi += PERSONA_BATCH) {
    const batch = parties.slice(bi, bi + PERSONA_BATCH);
    onProgress?.(`Forum prep: personas ${bi + 1}-${Math.min(bi + PERSONA_BATCH, parties.length)} of ${parties.length}`);
    const batchResults = await Promise.all(batch.map(async (party) => {
      const personaInput = `PARTY: ${party.name}
TYPE: ${party.type}
AGENDA: ${party.agenda}
MEANS: ${party.means.join(", ")}
STANCE: ${party.stance}
TOPIC: ${title}`;
      let personaRaw;
      if (personaConfig.tools.length > 0) {
        personaRaw = await runAgenticLoop({
          model: personaModel,
          messages: [
            { role: "system", content: personaConfig.content },
            { role: "user", content: personaInput }
          ],
          tools: personaConfig.tools,
          topicId,
          stage: "forum_prep",
          temperature: 0.4,
          max_tokens: 400
        });
      } else {
        personaRaw = await chatCompletionText({
          model: personaModel,
          messages: [
            { role: "system", content: personaConfig.content },
            { role: "user", content: personaInput }
          ],
          temperature: 0.4,
          max_tokens: 400
        });
      }
      let personaTitle = party.name + " Representative";
      let personaPrompt = personaRaw.trim();
      try {
        const match = personaRaw.match(/\{[\s\S]+\}/);
        if (match) {
          const parsed = JSON.parse(match[0]);
          personaTitle = parsed.title || personaTitle;
          personaPrompt = parsed.prompt || personaPrompt;
        }
      } catch {}
      const isLowWeight = (party.weight ?? 0) < LOW_WEIGHT_THRESHOLD;
      const budget = computeSpeakingBudget(party.weight ?? 0, totalWeight, isLowWeight);
      const rep = {
        id: `rep-${party.id}`,
        party_id: party.id,
        persona_prompt: personaPrompt,
        persona_title: personaTitle,
        speaking_weight: party.weight ?? 0,
        speaking_budget: budget,
        auto_generated: true
      };
      emitThink(topicId, "\uD83C\uDFAD", `Representative created \xB7 ${party.name}`, `${personaTitle} \xB7 weight ${party.weight}`);
      return rep;
    }));
    representatives.push(...batchResults);
  }
  dbSetRepresentatives(topicId, representatives);
  const output = {
    topic_id: topicId,
    run_id: runId,
    representatives: representatives.map((r2) => ({ party_id: r2.party_id, persona_title: r2.persona_title, speaking_weight: r2.speaking_weight }))
  };
  await writeArtifact(topicId, runId, "forum_prep", output);
  log.weight(`Forum prep complete: ${representatives.map((r2) => `${r2.party_id}=${r2.speaking_weight}w (opening=${r2.speaking_budget.opening_statement}w)`).join(", ")}`);
  onProgress?.(`Forum prep: done. ${representatives.length} representatives created`);
  return output;
}

