// src/agents/RepresentativeAgent.ts
init_logger();
function countWords(text3) {
  return text3.trim().split(/\s+/).filter(Boolean).length;
}
function formatScratchpad(content) {
  const clueLines = content.clue_analysis.filter((c) => {
    const rel = c.r ?? c.relevance_to_us;
    return rel !== "N" && rel !== "neutral";
  }).slice(0, 12).map((c) => {
    const rel = c.r ?? (c.relevance_to_us === "supports" ? "S" : c.relevance_to_us === "weakens" ? "W" : "N");
    const use = c.use || c.how_we_use_it || "";
    return `  [${c.clue_id}] ${rel}: ${use.slice(0, 100)}`;
  });
  return [
    `YOUR CORE POSITION: ${content.our_core_position}`,
    `SCENARIO YOU ARE PUSHING: ${content.scenario_we_are_pushing}`,
    `STRONGEST OPPONENT: ${content.strongest_opposing_party}`,
    `YOUR VULNERABILITIES: ${content.our_key_vulnerabilities.join("; ")}`,
    `YOUR OPENING MOVE: ${content.opening_move}`,
    `
CLUE STRATEGY (non-neutral clues):`,
    ...clueLines
  ].join(`
`);
}
function formatRecentTurns(turns) {
  return turns.map((t2) => `[Turn ${t2.round} \u2014 ${t2.party_name}]: ${t2.statement}`).join(`

---

`);
}
function formatScenarios(scenarios) {
  if (scenarios.length === 0)
    return "No scenarios defined yet.";
  return scenarios.map((s) => `\u2022 ${s.title}: ${s.description} (supported by: ${s.supported_by.join(", ") || "none"}, contested by: ${s.contested_by.join(", ") || "none"})`).join(`
`);
}
async function runRepresentativeTurn(input) {
  const {
    topicId,
    runId,
    sessionId,
    partyId,
    personaTitle,
    model,
    turnNumber,
    myTurnCount,
    speakingWeight,
    recentTurns,
    compressedHistory,
    liveScenarios,
    topic,
    moderatorDirective
  } = input;
  const party = await getPartyProfile(topicId, partyId);
  const repId = `rep-${partyId}`;
  const scratchpadRow = dbGetScratchpad(topicId, sessionId, repId);
  const scratchpadStr = scratchpadRow ? formatScratchpad(scratchpadRow.content) : `YOUR CORE POSITION: ${party.agenda}
No detailed preparation available.`;
  const historyBlock = compressedHistory ? `DEBATE SUMMARY (earlier turns):
${compressedHistory}

` : "";
  const recentStr = formatRecentTurns(recentTurns);
  const scenariosStr = formatScenarios(liveScenarios);
  const directiveBlock = moderatorDirective ? `
MODERATOR NOTE: ${moderatorDirective}
` : "";
  const turnConfig = await resolvePrompt("forum/representative-turn", {
    persona_title: personaTitle,
    party_name: party.name,
    scratchpad: scratchpadStr,
    topic,
    live_scenarios: scenariosStr,
    conversation_history: historyBlock,
    recent_turns: recentStr,
    my_turn_count: String(myTurnCount),
    turn_number: String(turnNumber),
    speaking_weight: String(speakingWeight),
    moderator_directive: directiveBlock
  });
  const effectiveModel = turnConfig.model ?? model;
  const userContent = `Turn ${turnNumber}: It is your moment. Speak or pass.`;
  const budget = budgetOutput(effectiveModel, turnConfig.content + userContent, { min: 300, max: 800 });
  let raw;
  try {
    if (turnConfig.tools.length > 0) {
      raw = await runAgenticLoop({
        model: effectiveModel,
        topicId,
        stage: "forum",
        tools: turnConfig.tools,
        temperature: 0.7,
        max_tokens: budget,
        messages: [
          { role: "system", content: turnConfig.content },
          { role: "user", content: userContent }
        ]
      });
    } else {
      raw = await chatCompletionText({
        model: effectiveModel,
        messages: [
          { role: "system", content: turnConfig.content },
          { role: "user", content: userContent }
        ],
        temperature: 0.7,
        max_tokens: budget
      });
    }
  } catch (e) {
    log.forum(`  ${partyId} turn failed: ${e}`);
    return { turn: null, passed: true };
  }
  let action = "speak";
  let statement = "";
  let cluesCited = [];
  let scenarioSignal;
  try {
    const cleaned = raw.replace(/```json\s*/gi, "").replace(/```\s*/g, "");
    const match = cleaned.match(/\{[\s\S]+\}/);
    if (match) {
      const parsed = JSON.parse(match[0]);
      action = parsed.action === "pass" ? "pass" : "speak";
      statement = parsed.statement || "";
      cluesCited = parsed.clues_cited || [];
      scenarioSignal = parsed.scenario_signal || undefined;
    } else {
      statement = raw.trim();
    }
  } catch {
    statement = raw.trim();
  }
  if (action === "pass") {
    log.forum(`  ${partyId} PASSED turn ${turnNumber}`);
    return { turn: null, passed: true };
  }
  const inlineCites = statement.match(/\[clue-\d+\]/g) ?? [];
  const allCited = [...new Set([...cluesCited, ...inlineCites.map((m2) => m2.replace(/[\[\]]/g, ""))])];
  const turn = {
    id: `turn-${partyId}-t${turnNumber}`,
    representative_id: repId,
    party_name: party.name,
    persona_title: personaTitle,
    statement,
    clues_cited: allCited,
    scenario_endorsement: scenarioSignal,
    timestamp: new Date().toISOString(),
    round: turnNumber,
    type: "debate",
    word_count: countWords(statement),
    evidence: [],
    challenges: [],
    concessions: []
  };
  await writeArtifact(topicId, runId, `turn_${partyId}_t${turnNumber}`, turn);
  log.forum(`  ${partyId} spoke (${turn.word_count}w, cited ${allCited.length} clues): "${statement.slice(0, 80)}\u2026"`);
  return { turn, passed: false };
}

// src/agents/ForumSupervisor.ts
init_proxyClient();
init_tokenBudget();
init_promptLoader();
init_agenticLoop();
init_settings();
init_logger();
init_stream2();
var DEFAULT_MAX_TURNS = 50;
var COMPRESS_INTERVAL = 10;

class ForumSupervisor {
  state;
  topicId;
  model;
  topic;
  maxTurns;
  minTurns;
  checkInterval;
  compressInterval;
  constructor(topicId, sessionId, model, topic, maxTurns = DEFAULT_MAX_TURNS, minTurns = 8) {
    this.topicId = topicId;
    this.model = model;
    this.topic = topic;
    this.maxTurns = maxTurns;
    this.minTurns = minTurns;
    const controls = dbGetControls();
    this.checkInterval = controls.forum_scenario_update_interval ?? 5;
    this.compressInterval = controls.forum_compress_interval;
    this.state = {
      session_id: sessionId,
      topic_id: topicId,
      turn_count: 0,
      turn_distribution: {},
      live_scenarios: [],
      compressed_history: "",
      status: "running",
      updated_at: new Date().toISOString()
    };
    this.persist();
  }
  get turnCount() {
    return this.state.turn_count;
  }
  get liveScenarios() {
    return this.state.live_scenarios;
  }
  get compressedHistory() {
    return this.state.compressed_history;
  }
  get turnDistribution() {
    return this.state.turn_distribution;
  }
  get isDone() {
    return this.state.status === "done";
  }
  recentSpeakers = [];
  observeTurn(turn) {
    this.state.turn_count++;
    const partyId = turn.representative_id.replace("rep-", "");
    this.state.turn_distribution[partyId] = (this.state.turn_distribution[partyId] ?? 0) + 1;
    this.recentSpeakers.push(partyId);
    if (this.recentSpeakers.length > 6)
      this.recentSpeakers.shift();
    this.state.updated_at = new Date().toISOString();
    this.persist();
  }
  detectExchangeLoop() {
    if (this.recentSpeakers.length < 4)
      return { looping: false, parties: [] };
    const last4 = this.recentSpeakers.slice(-4);
    const unique = [...new Set(last4)];
    return { looping: unique.length <= 2, parties: unique };
  }
  computeSilentParties(representatives) {
    const silent = [];
    for (const r2 of representatives) {
      const lastSpoke = this.recentSpeakers.lastIndexOf(r2.party_id);
      const turnsSince = lastSpoke === -1 ? this.state.turn_count : this.recentSpeakers.length - 1 - lastSpoke + Math.max(0, this.state.turn_count - this.recentSpeakers.length);
      if (turnsSince >= 8 && (this.state.turn_distribution[r2.party_id] ?? 0) > 0) {
        silent.push(r2.party_id);
      } else if ((this.state.turn_distribution[r2.party_id] ?? 0) === 0 && this.state.turn_count >= 3) {
        silent.push(r2.party_id);
      }
    }
    return silent;
  }
  computeBudgetWarning() {
    const softCeiling = Math.round(this.minTurns * 1.3);
    const hardRemaining = this.maxTurns - this.state.turn_count;
    const softRemaining = softCeiling - this.state.turn_count;
    if (hardRemaining <= 3) {
      return `FINAL TURNS: Only ${hardRemaining} turns before hard limit. The next speaker must deliver a closing synthesis.`;
    }
    if (this.state.turn_count >= softCeiling) {
      return `OVER EXPECTED LENGTH: The debate has passed its expected ${softCeiling}-turn length. Close the debate unless there is a critical unresolved argument that no party has addressed.`;
    }
    if (softRemaining <= 3 && softRemaining > 0) {
      return `WRAP-UP PHASE: ${softRemaining} turns until expected end at turn ${softCeiling}. Start directing parties toward their final positions and conclusions.`;
    }
    return "";
  }
  async moderate(lastTurn, representatives) {
    if (this.state.turn_count >= this.maxTurns) {
      const reason = `Hard ceiling of ${this.maxTurns} turns reached`;
      this.markDone(reason);
      return {
        next_speaker: null,
        reason,
        directive: null,
        should_close: true,
        coverage_score: 75,
        closure_reason: reason
      };
    }
    const loop = this.detectExchangeLoop();
    if (loop.looping) {
      const fallback = this.deficitFallback(representatives.filter((r2) => !loop.parties.includes(r2.party_id)));
      const [a12, b] = loop.parties;
      log.forum(`  Exchange limit: breaking ${a12} vs ${b} loop \u2014 giving floor to ${fallback.party_id}`);
      emitThink(this.topicId, "\u2696\uFE0F", `Breaking exchange loop`, `${a12} vs ${b} \u2192 ${fallback.party_id}`);
      return {
        next_speaker: fallback.party_id,
        reason: `Breaking ${a12} vs ${b} exchange loop \u2014 other parties need the floor`,
        directive: `We've heard extensive exchange between the previous speakers. Let's hear a fresh perspective.`,
        should_close: false,
        coverage_score: Math.min(50, this.state.turn_count * 2)
      };
    }
    const totalWeight = representatives.reduce((s, r2) => s + r2.speaking_weight, 0) || 1;
    const softCeiling = Math.round(this.minTurns * 1.3);
    const partiesList = representatives.map((r2) => {
      const count = this.state.turn_distribution[r2.party_id] ?? 0;
      const share = r2.speaking_weight / totalWeight;
      const expectedTurns = Math.round(share * softCeiling);
      return `- ${r2.party_id} (priority=${Math.round(share * 100)}%, turns=${count}/${expectedTurns})`;
    }).join(`
`);
    const turnDistribution = Object.entries(this.state.turn_distribution).map(([id, count]) => `${id}: ${count} turns`).join(", ");
    const recentSpeakersStr = this.recentSpeakers.length > 0 ? this.recentSpeakers.slice(-4).join(" \u2192 ") : "None yet";
    const silentParties = this.computeSilentParties(representatives);
    const silentPartiesStr = silentParties.length > 0 ? `SILENT PARTIES (haven't spoken in 8+ turns): ${silentParties.join(", ")}` : "";
    const budgetWarning = this.computeBudgetWarning();
    const scenariosSummary = this.state.live_scenarios.length > 0 ? this.state.live_scenarios.map((s) => `\u2022 ${s.title} (for: ${s.supported_by.join(", ")}, against: ${s.contested_by.join(", ")})`).join(`
`) : "No scenarios yet";
    let lastTurnStr;
    if (lastTurn) {
      const cluesPart = lastTurn.clues_cited.length > 0 ? ` (cited: ${lastTurn.clues_cited.join(", ")})` : "";
      const full = `[${lastTurn.party_name}]: ${lastTurn.statement}${cluesPart}`;
      lastTurnStr = full.length > 500 ? full.slice(0, 500) + "\u2026" : full;
    } else {
      lastTurnStr = "This is the first turn of the debate.";
    }
    try {
      const promptConfig = await resolvePrompt("forum/supervisor-moderate", {
        topic: this.topic,
        parties_list: partiesList,
        turn_distribution: turnDistribution || "No turns yet",
        turn_number: String(this.state.turn_count + 1),
        soft_ceiling: String(softCeiling),
        hard_limit: String(this.maxTurns),
        min_turns: String(this.minTurns),
        recent_speakers: recentSpeakersStr,
        silent_parties: silentPartiesStr,
        budget_warning: budgetWarning,
        scenarios_summary: scenariosSummary,
        last_turn: lastTurnStr
      });
      const effectiveModel = promptConfig.model ?? this.model;
      const budget = budgetOutput(effectiveModel, promptConfig.content, { min: 200, max: 500 });
      const raw = await chatCompletionText({
        model: effectiveModel,
        messages: [
          { role: "system", content: promptConfig.content },
          { role: "user", content: "Moderate the next turn." }
        ],
        temperature: 0.3,
        max_tokens: budget
      });
      const match = raw.match(/\{[\s\S]+\}/);
      if (!match)
        throw new Error("No JSON in moderate response");
      const decision = JSON.parse(match[0]);
      if (decision.should_close) {
        this.markDone(decision.closure_reason ?? decision.reason);
      }
      emitThink(this.topicId, "\uD83C\uDFAF", `Moderator \u2192 ${decision.next_speaker}`, decision.reason);
      return decision;
    } catch (e) {
      log.forum(`  Supervisor moderate failed: ${e} \u2014 falling back to deficit-based pick`);
      const fallback = this.deficitFallback(representatives);
      const decision = {
        next_speaker: fallback.party_id,
        reason: "Fallback: deficit-based selection after moderate error",
        directive: null,
        should_close: false,
        coverage_score: 50
      };
      emitThink(this.topicId, "\uD83C\uDFAF", `Moderator \u2192 ${decision.next_speaker}`, decision.reason);
      return decision;
    }
  }
  deficitFallback(reps) {
    const total = Math.max(this.state.turn_count, 1);
    let best = reps[0];
    let bestDeficit = -Infinity;
    for (const r2 of reps) {
      const expectedShare = r2.speaking_weight / 100;
      const actualCount = this.state.turn_distribution[r2.party_id] ?? 0;
      const deficit = expectedShare - actualCount / total;
      if (deficit > bestDeficit) {
        bestDeficit = deficit;
        best = r2;
      }
    }
    return best;
  }
  async updateScenarios(allTurns) {
    if (allTurns.length === 0)
      return this.state.live_scenarios;
    const turnsStr = allTurns.map((t2) => `[${t2.party_name} T${t2.round}]: ${t2.statement.slice(0, 250)}`).join(`

`);
    const currentScenariosStr = JSON.stringify(this.state.live_scenarios, null, 2);
    const scenariosConfig = await resolvePrompt("forum/supervisor-scenarios", {
      topic: this.topic,
      current_scenarios: currentScenariosStr,
      all_turns: turnsStr
    });
    const effectiveModel = scenariosConfig.model ?? this.model;
    const scenarioMax = Math.max(4000, this.state.live_scenarios.length * 700);
    const budget = budgetOutput(effectiveModel, scenariosConfig.content, { min: 1500, max: scenarioMax });
    try {
      let raw;
      if (scenariosConfig.tools.length > 0) {
        raw = await runAgenticLoop({
          model: effectiveModel,
          topicId: this.topicId,
          stage: "forum",
          tools: scenariosConfig.tools,
          temperature: 0.2,
          max_tokens: budget,
          messages: [
            { role: "system", content: scenariosConfig.content },
            { role: "user", content: "Update the scenario list based on the debate so far." }
          ]
        });
      } else {
        raw = await chatCompletionText({
          model: effectiveModel,
          messages: [
            { role: "system", content: scenariosConfig.content },
            { role: "user", content: "Update the scenario list based on the debate so far." }
          ],
          temperature: 0.2,
          max_tokens: budget
        });
      }
      const match = raw.match(/\[[\s\S]+\]/);
      if (!match)
        throw new Error("No JSON array in scenarios response");
      const updated = JSON.parse(match[0]);
      this.state.live_scenarios = updated;
      this.persist();
      log.forum(`  Supervisor: ${updated.length} scenarios tracked`);
      emitThink(this.topicId, "\uD83D\uDCCA", `Scenarios updated`, `${updated.length} scenarios on the table`);
      return updated;
    } catch (e) {
      log.forum(`  Supervisor scenario update failed: ${e}`);
      return this.state.live_scenarios;
    }
  }
  async compressHistory(allTurns) {
    if (allTurns.length < this.compressInterval)
      return;
    const toCompress = allTurns.slice(0, -8);
    if (toCompress.length === 0)
      return;
    const turnsStr = toCompress.map((t2) => `[${t2.party_name}]: ${t2.statement.slice(0, 300)}`).join(`

`);
    try {
      const raw = await chatCompletionText({
        model: this.model,
        messages: [
          {
            role: "system",
            content: "You are summarizing a geopolitical debate transcript. Produce a dense, neutral summary that preserves: who argued what position, which clues were cited and how, which scenarios emerged, and any key concessions or disputes. Preserve clue IDs. Be comprehensive \u2014 this replaces the original transcript."
          },
          { role: "user", content: `Summarize this debate transcript:

${turnsStr}` }
        ],
        temperature: 0.2,
        max_tokens: 1500
      });
      this.state.compressed_history = raw.trim();
      this.persist();
      log.forum(`  Supervisor: history compressed (${toCompress.length} turns \u2192 ${raw.length} chars)`);
    } catch (e) {
      log.forum(`  History compression failed: ${e}`);
    }
  }
  markDone(reason) {
    this.state.status = "done";
    this.state.closure_reason = reason;
    this.state.updated_at = new Date().toISOString();
    this.persist();
  }
  persist() {
    dbUpsertSupervisorState(this.topicId, this.state);
  }
}

// src/agents/ForumOrchestrator.ts
init_stream2();
function turnBatch(turnNumber) {
  return Math.floor((turnNumber - 1) / 10) + 1;
}
async function runForumOrchestrator(topicId, runId, sessionId, model, _checkpoint, onProgress, version) {
  const representatives = dbGetRepresentatives(topicId);
  if (!representatives.length)
    throw new Error("No representatives found");
  log.separator();
  log.forum(`Forum starting: ${representatives.length} parties, session=${sessionId}`);
  log.forum(`Parties: ${representatives.map((r2) => `${r2.party_id}(w=${r2.speaking_weight})`).join(", ")}`);
  log.separator();
  const session = {
    session_id: sessionId,
    version: version ?? 1,
    type: "full",
    status: "running",
    started_at: new Date().toISOString(),
    rounds: [],
    scenarios: []
  };
  await writeForumSession(topicId, session);
  log.forum("Starting fresh forum session");
  const { dbGetTopic: dbGetTopic2 } = await Promise.resolve().then(() => (init_topics(), exports_topics));
  const topicRow = dbGetTopic2(topicId);
  const topicTitle = topicRow?.title ?? topicId;
  const controls = dbGetControls();
  const maxTurns = controls.forum_max_turns;
  const multiplier = controls.forum_min_turns_multiplier ?? 2.5;
  const minTurns = Math.max(15, Math.floor(representatives.length * multiplier));
  onProgress?.("Forum: agents preparing scratchpads\u2026");
  emit(topicId, { type: "progress", stage: "forum", pct: 0.02, msg: "Representatives preparing\u2026" });
  await runForumPrepAgent(topicId, topicTitle, sessionId, model, onProgress);
  emit(topicId, { type: "progress", stage: "forum", pct: 0.1, msg: "All representatives ready. Debate opening\u2026" });
  const supervisor = new ForumSupervisor(topicId, sessionId, model, topicTitle, maxTurns, minTurns);
  const scenarioInterval = controls.forum_scenario_update_interval ?? 5;
  const allTurns = session.rounds.flatMap((r2) => r2.turns);
  let turnNumber = allTurns.length + 1;
  let lastTurn = allTurns.at(-1) ?? null;
  log.forum(`Debate opening at turn ${turnNumber} (max=${maxTurns}, min=${minTurns})`);
  emitThink(topicId, "\uD83C\uDF99\uFE0F", "Forum is open", `${representatives.length} parties ready to debate`);
  while (!supervisor.isDone) {
    const decision = await supervisor.moderate(lastTurn, representatives);
    if (decision.should_close) {
      log.forum(`Debate closed by moderator at turn ${allTurns.length}: ${decision.closure_reason ?? decision.reason}`);
      emit(topicId, { type: "progress", stage: "forum", pct: 0.8, msg: `Moderator closed debate: ${decision.coverage_score}% coverage` });
      break;
    }
    const selected = representatives.find((r2) => r2.party_id === decision.next_speaker);
    if (!selected) {
      log.forum(`Moderator picked unknown party "${decision.next_speaker}", falling back to first rep`);
      break;
    }
    onProgress?.(`Forum turn ${turnNumber}: ${selected.party_id}`);
    const myTurnCount = supervisor.turnDistribution[selected.party_id] ?? 0;
    const { turn, passed } = await runRepresentativeTurn({
      topicId,
      runId,
      sessionId,
      partyId: selected.party_id,
      personaTitle: selected.persona_title,
      model,
      turnNumber,
      myTurnCount,
      speakingWeight: selected.speaking_weight,
      recentTurns: allTurns.slice(-6),
      compressedHistory: supervisor.compressedHistory,
      liveScenarios: supervisor.liveScenarios,
      topic: topicTitle,
      moderatorDirective: decision.directive ?? undefined
    });
    if (passed) {
      log.forum(`  ${selected.party_id} passed turn ${turnNumber}`);
    } else if (turn) {
      if (decision.directive)
        turn.moderator_directive = decision.directive;
      if (decision.reason)
        turn.moderator_reason = decision.reason;
      allTurns.push(turn);
      lastTurn = turn;
      const batchNum = turnBatch(turnNumber);
      let roundEntry = session.rounds.find((r2) => r2.round === batchNum);
      if (!roundEntry) {
        roundEntry = { round: batchNum, type: "debate", turns: [] };
        session.rounds.push(roundEntry);
      }
      roundEntry.turns.push(turn);
      await writeForumSession(topicId, session);
      emit(topicId, { type: "forum_turn", turn });
      supervisor.observeTurn(turn);
      turnNumber++;
      if (allTurns.length % scenarioInterval === 0) {
        const scenarios = await supervisor.updateScenarios(allTurns);
        session.scenarios = scenarios;
        await writeForumSession(topicId, session);
        emit(topicId, { type: "progress", stage: "forum", pct: Math.min(0.1 + allTurns.length / maxTurns * 0.7, 0.8), msg: `Turn ${allTurns.length}: ${decision.coverage_score}% coverage` });
      }
      if (allTurns.length % COMPRESS_INTERVAL === 0) {
        await supervisor.compressHistory(allTurns);
      }
    }
  }
  log.forum(`Debate ended after ${allTurns.length} turns`);
  emit(topicId, { type: "progress", stage: "forum", pct: 0.85, msg: "Finalizing scenarios\u2026" });
  const finalScenarios = await supervisor.updateScenarios(allTurns);
  session.scenarios = finalScenarios;
  if (finalScenarios.length > 0) {
    const sorted = [...finalScenarios].sort((a12, b) => b.supported_by.length - a12.supported_by.length);
    session.scenarios = sorted;
    await writeForumSession(topicId, session);
  }
  emit(topicId, { type: "progress", stage: "forum", pct: 0.9, msg: "Synthesizing debate summary\u2026" });
  const allScratchpads = dbGetAllScratchpads(topicId, sessionId);
  const debateSummary = await synthesizeDebate(topicTitle, allTurns, finalScenarios, model);
  const contestedClues = computeContestedClues(allTurns);
  const uncontestedClues = computeUncontestedClues(allTurns, contestedClues);
  session.scenario_summary = {
    scenarios: finalScenarios.map((s) => ({
      id: s.id,
      title: s.title,
      key_clues: s.clues_cited,
      required_conditions: s.required_conditions,
      falsification_conditions: s.falsification_conditions
    })),
    contested_clues: contestedClues,
    uncontested_clues: uncontestedClues
  };
  session.status = "complete";
  session.completed_at = new Date().toISOString();
  await writeForumSession(topicId, session);
  const output = {
    session_id: sessionId,
    turns_completed: allTurns.length,
    scenario_count: finalScenarios.length,
    closure_reason: supervisor.isDone ? "supervisor" : "max_turns"
  };
  await writeArtifact(topicId, runId, "forum_orchestrator", {
    ...output,
    debate_summary: debateSummary,
    scratchpads: allScratchpads.map((s) => ({ party_id: s.party_id, content: s.content }))
  });
  emit(topicId, { type: "stage_complete", stage: "forum", session_id: sessionId });
  log.forum(`Forum complete: ${allTurns.length} turns, ${finalScenarios.length} scenarios`);
  return output;
}
async function synthesizeDebate(topic, allTurns, scenarios, model) {
  const turnsStr = allTurns.map((t2) => `[${t2.party_name}]: ${t2.statement.slice(0, 200)}`).join(`

`);
  const scenariosStr = scenarios.map((s) => `\u2022 ${s.title}: ${s.description} (for: ${s.supported_by.join(", ")}, against: ${s.contested_by.join(", ")})`).join(`
`);
  try {
    return await chatCompletionText({
      model,
      messages: [
        {
          role: "system",
          content: "You are summarizing a multi-party geopolitical forum debate for expert analysts. Produce a 4-6 paragraph dense summary covering: the main positions argued, key clues cited and disputed, how scenarios emerged from the debate, and where parties found unexpected common ground or irreconcilable disagreement. Preserve clue IDs inline."
        },
        {
          role: "user",
          content: `TOPIC: ${topic}

SCENARIOS THAT EMERGED:
${scenariosStr}

DEBATE TRANSCRIPT (truncated):
${turnsStr.slice(0, 12000)}`
        }
      ],
      temperature: 0.3,
      max_tokens: budgetOutput(model, turnsStr.slice(0, 12000) + scenariosStr, { min: 800, max: 2000 })
    });
  } catch {
    return "Debate summary unavailable.";
  }
}
function computeContestedClues(turns) {
  const clueRepMap = new Map;
  for (const t2 of turns) {
    for (const cid of t2.clues_cited) {
      if (!clueRepMap.has(cid))
        clueRepMap.set(cid, new Set);
      clueRepMap.get(cid).add(t2.representative_id);
    }
  }
  const contested = [];
  for (const [clueId, reps] of clueRepMap.entries()) {
    if (reps.size >= 2) {
      contested.push({
        clue_id: clueId,
        cited_by: [...reps],
        conflict: `Cited by ${reps.size} different parties with potentially conflicting interpretations`
      });
    }
  }
  return contested;
}
function computeUncontestedClues(turns, contested) {
  const contestedIds = new Set(contested.map((c) => c.clue_id));
  const allCited = new Set(turns.flatMap((t2) => t2.clues_cited));
  return [...allCited].filter((id) => !contestedIds.has(id));
}

