// src/db/queries/expert.ts
init_database();
function dbSaveExpertCouncil(topicId, output) {
  const db = getDb();
  const txn = db.transaction(() => {
    const existing = db.query("SELECT id FROM expert_councils WHERE topic_id = ? AND version = ?").get(topicId, output.version);
    if (existing) {
      db.run("DELETE FROM final_verdicts WHERE council_id = ?", [existing.id]);
      db.run("DELETE FROM expert_assessments WHERE council_id = ?", [existing.id]);
      db.run("DELETE FROM expert_councils WHERE id = ?", [existing.id]);
    }
    db.run(`INSERT INTO expert_councils (topic_id, version, verdict_id, created_at, experts)
       VALUES (?, ?, ?, ?, ?)`, [topicId, output.version, output.verdict_id, new Date().toISOString(), JSON.stringify(output.experts)]);
    const councilId = db.query("SELECT last_insert_rowid() as id").get().id;
    for (const d of output.deliberations) {
      db.run(`INSERT INTO expert_assessments (council_id, topic_id, expert_id, expert_name, domain, scenario_assessments, weight_challenges, deliberation_text)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?)`, [
        councilId,
        topicId,
        d.expert_id,
        d.expert_name,
        d.domain,
        JSON.stringify(d.scenario_assessments),
        JSON.stringify(d.weight_challenges),
        d.cross_deliberation_response ?? null
      ]);
    }
    if (output.final_verdict) {
      const v = output.final_verdict;
      db.run(`INSERT INTO final_verdicts (council_id, topic_id, synthesized_at, scenarios_ranked, final_assessment, confidence_note, weight_challenge_decisions)
         VALUES (?, ?, ?, ?, ?, ?, ?)`, [
        councilId,
        topicId,
        v.synthesized_at,
        JSON.stringify(v.scenarios_ranked),
        v.final_assessment,
        v.confidence_note,
        JSON.stringify(v.weight_challenge_decisions)
      ]);
    }
  });
  txn();
}
function dbGetExpertCouncil(topicId, version) {
  const db = getDb();
  const councilRow = db.query("SELECT * FROM expert_councils WHERE topic_id = ? AND version = ?").get(topicId, version);
  if (!councilRow)
    return null;
  const assessmentRows = db.query("SELECT * FROM expert_assessments WHERE council_id = ?").all(councilRow.id);
  const deliberations = assessmentRows.map((r2) => ({
    expert_id: r2.expert_id,
    expert_name: r2.expert_name,
    domain: r2.domain,
    scenario_assessments: JSON.parse(r2.scenario_assessments),
    weight_challenges: JSON.parse(r2.weight_challenges),
    cross_deliberation_response: r2.deliberation_text ?? undefined
  }));
  const verdictRow = db.query("SELECT * FROM final_verdicts WHERE council_id = ?").get(councilRow.id);
  const finalVerdict = verdictRow ? {
    synthesized_at: verdictRow.synthesized_at,
    scenarios_ranked: JSON.parse(verdictRow.scenarios_ranked),
    final_assessment: verdictRow.final_assessment,
    confidence_note: verdictRow.confidence_note,
    weight_challenge_decisions: JSON.parse(verdictRow.weight_challenge_decisions)
  } : undefined;
  return {
    version: councilRow.version,
    verdict_id: councilRow.verdict_id ?? `verdict-v${councilRow.version}`,
    experts: JSON.parse(councilRow.experts),
    deliberations,
    final_verdict: finalVerdict
  };
}
function dbGetLatestExpertCouncil(topicId) {
  const row = getDb().query("SELECT version FROM expert_councils WHERE topic_id = ? ORDER BY version DESC LIMIT 1").get(topicId);
  if (!row)
    return null;
  return dbGetExpertCouncil(topicId, row.version);
}

// src/agents/ScenarioScorer.ts
init_topics();
function computeEffectiveWeight(credibility, biasFlags) {
  return Math.max(0.1, credibility - biasFlags.length * 0.1);
}
function buildEvidenceMap(scenarios, allTurns, scratchpads, parties, clueMap) {
  const partyMap = new Map(parties.map((p) => [p.id, p]));
  const clueCitedBy = new Map;
  for (const turn of allTurns) {
    for (const cId of turn.clues_cited) {
      if (!clueCitedBy.has(cId))
        clueCitedBy.set(cId, []);
      clueCitedBy.get(cId).push(turn.party_id ?? turn.representative_id.replace("rep-", ""));
    }
  }
  const partyTurnCount = new Map;
  for (const turn of allTurns) {
    const pid = turn.party_id ?? turn.representative_id.replace("rep-", "");
    partyTurnCount.set(pid, (partyTurnCount.get(pid) ?? 0) + 1);
  }
  return scenarios.map((sc) => {
    const scClueIds = new Set(sc.clues_cited);
    const supportingPartyIds = new Set(sc.supported_by);
    const contestingPartyIds = new Set(sc.contested_by);
    for (const turn of allTurns) {
      const pid = turn.party_id ?? turn.representative_id.replace("rep-", "");
      if (supportingPartyIds.has(pid)) {
        for (const cId of turn.clues_cited)
          scClueIds.add(cId);
      }
    }
    const supportingClues = [];
    for (const cId of scClueIds) {
      const clue = clueMap.get(cId);
      if (!clue)
        continue;
      supportingClues.push({
        clue_id: cId,
        title: clue.title,
        clue_type: clue.clue_type,
        credibility: clue.credibility,
        bias_flags: clue.bias_flags,
        effective_weight: computeEffectiveWeight(clue.credibility, clue.bias_flags),
        summary: clue.summary,
        cited_in_turns: (clueCitedBy.get(cId) ?? []).length
      });
    }
    const contestingClues = [];
    for (const turn of allTurns) {
      const pid = turn.party_id ?? turn.representative_id.replace("rep-", "");
      if (!contestingPartyIds.has(pid))
        continue;
      for (const cId of turn.clues_cited) {
        if (scClueIds.has(cId))
          continue;
        const clue = clueMap.get(cId);
        if (!clue)
          continue;
        if (contestingClues.some((c) => c.clue_id === cId))
          continue;
        contestingClues.push({
          clue_id: cId,
          title: clue.title,
          clue_type: clue.clue_type,
          credibility: clue.credibility,
          bias_flags: clue.bias_flags,
          effective_weight: computeEffectiveWeight(clue.credibility, clue.bias_flags),
          summary: clue.summary,
          cited_in_turns: (clueCitedBy.get(cId) ?? []).length
        });
      }
    }
    const forumFor = sc.supported_by.map((pid) => {
      const party = partyMap.get(pid);
      return { party_id: pid, party_name: party?.name ?? pid, weight: party?.weight ?? 0, turn_count: partyTurnCount.get(pid) ?? 0 };
    });
    const forumAgainst = sc.contested_by.map((pid) => {
      const party = partyMap.get(pid);
      return { party_id: pid, party_name: party?.name ?? pid, weight: party?.weight ?? 0, turn_count: partyTurnCount.get(pid) ?? 0 };
    });
    const scratchpadPushers = [];
    const scratchpadResisters = [];
    for (const pad of scratchpads) {
      const party = partyMap.get(pad.party_id);
      if (!party)
        continue;
      const push2 = pad.content.scenario_we_are_pushing ?? "";
      const vulns = pad.content.our_key_vulnerabilities ?? [];
      const scTitle = sc.title.toLowerCase();
      const pushLower = push2.toLowerCase();
      if (pushLower.length > 0 && (scTitle.split(" ").filter((w) => w.length > 4).some((w) => pushLower.includes(w)) || sc.benefiting_parties.includes(pad.party_id))) {
        scratchpadPushers.push({ party_id: pad.party_id, party_name: party.name, weight: party.weight, scenario_push: push2.slice(0, 150) });
      }
      for (const vuln of vulns) {
        if (scTitle.split(" ").filter((w) => w.length > 4).some((w) => vuln.toLowerCase().includes(w))) {
          scratchpadResisters.push({ party_id: pad.party_id, party_name: party.name, weight: party.weight, vulnerability: vuln.slice(0, 100) });
          break;
        }
      }
    }
    const backingWeight = [
      ...forumFor.map((p) => p.weight),
      ...scratchpadPushers.map((p) => p.weight)
    ].reduce((s, w) => s + w, 0);
    const blockingWeight = [
      ...forumAgainst.map((p) => p.weight),
      ...scratchpadResisters.map((p) => p.weight)
    ].reduce((s, w) => s + w, 0);
    const netPowerProjection = backingWeight - blockingWeight;
    const evidenceDensity = supportingClues.reduce((s, c) => s + c.effective_weight, 0);
    return {
      scenario_id: sc.id,
      title: sc.title,
      description: sc.description,
      supporting_clues: supportingClues,
      contesting_clues: contestingClues,
      forum_for: forumFor,
      forum_against: forumAgainst,
      scratchpad_pushers: scratchpadPushers,
      scratchpad_resisters: scratchpadResisters,
      net_power_projection: netPowerProjection,
      evidence_density: evidenceDensity
    };
  });
}
function serializeEvidenceMap(evidenceMap, parties) {
  const partyMap = new Map(parties.map((p) => [p.id, p]));
  const sections = [];
  for (const sc of evidenceMap) {
    const lines = [
      `=== SCENARIO: ${sc.scenario_id} \u2014 "${sc.title}" ===`,
      `Description: ${sc.description}`,
      `Net power projection: ${sc.net_power_projection > 0 ? "+" : ""}${Math.round(sc.net_power_projection)} (positive = backed by high-weight parties)`,
      `Evidence density score: ${sc.evidence_density.toFixed(2)}`
    ];
    if (sc.supporting_clues.length > 0) {
      lines.push(`
SUPPORTING CLUES (${sc.supporting_clues.length}):`);
      for (const c of sc.supporting_clues) {
        lines.push(`  [${c.clue_id}] ${c.title} | type=${c.clue_type} | credibility=${c.credibility.toFixed(2)} | bias_flags=[${c.bias_flags.join(", ")}] | effective_weight=${c.effective_weight.toFixed(2)} | cited_in_${c.cited_in_turns}_turns`);
        lines.push(`    Summary: ${c.summary.slice(0, 120)}`);
      }
    }
    if (sc.contesting_clues.length > 0) {
      lines.push(`
CONTESTING CLUES (${sc.contesting_clues.length}):`);
      for (const c of sc.contesting_clues) {
        lines.push(`  [${c.clue_id}] ${c.title} | effective_weight=${c.effective_weight.toFixed(2)}`);
        lines.push(`    Summary: ${c.summary.slice(0, 100)}`);
      }
    }
    if (sc.forum_for.length > 0) {
      lines.push(`
FORUM BACKING:`);
      for (const p of sc.forum_for) {
        const party = partyMap.get(p.party_id);
        const allies = party?.circle?.visible?.slice(0, 3).join(", ") ?? "none";
        lines.push(`  ${p.party_name} (weight=${p.weight}, turns=${p.turn_count}, allies=[${allies}])`);
      }
    }
    if (sc.forum_against.length > 0) {
      lines.push(`
FORUM OPPOSITION:`);
      for (const p of sc.forum_against) {
        lines.push(`  ${p.party_name} (weight=${p.weight}, turns=${p.turn_count})`);
      }
    }
    if (sc.scratchpad_pushers.length > 0) {
      lines.push(`
SCRATCHPAD INTEL \u2014 PRIVATELY PUSHING THIS SCENARIO:`);
      for (const p of sc.scratchpad_pushers) {
        lines.push(`  ${p.party_name} (weight=${p.weight}): "${p.scenario_push}"`);
      }
    }
    if (sc.scratchpad_resisters.length > 0) {
      lines.push(`
SCRATCHPAD INTEL \u2014 PRIVATELY VULNERABLE TO THIS SCENARIO:`);
      for (const p of sc.scratchpad_resisters) {
        lines.push(`  ${p.party_name} (weight=${p.weight}): "${p.vulnerability}"`);
      }
    }
    sections.push(lines.join(`
`));
  }
  const partySection = [
    `
=== PARTY REGISTRY ===`,
    ...parties.map((p) => {
      const allies = [...p.circle?.visible ?? [], ...p.circle?.shadow ?? []].slice(0, 4).join(", ");
      return `${p.name} (id=${p.id}, weight=${p.weight}, stance=${p.stance}, allies/shadow=[${allies}])`;
    })
  ].join(`
`);
  return sections.join(`

`) + `

` + partySection;
}
async function runScenarioScorer(topicId, runId, sessionId, model, onProgress, version) {
  const scorerConfig = await resolvePrompt("scoring/score-scenarios");
  const effectiveModel = scorerConfig.model ?? model;
  const SCORER_PROMPT = scorerConfig.content;
  log.separator();
  log.expert("Stage 5/5: SCENARIO SCORER starting");
  emitThink(topicId, "\uD83D\uDD2C", "Scenario Scorer", "Building evidence map from all sources");
  emit(topicId, { type: "progress", stage: "expert_council", pct: 0.1, msg: "Building evidence map..." });
  const [session, parties, rawClues, scratchpads] = await Promise.all([
    getForumSession(topicId, sessionId),
    Promise.resolve(dbGetParties(topicId)),
    Promise.resolve(dbGetClues(topicId)),
    Promise.resolve(dbGetAllScratchpads(topicId, sessionId))
  ]);
  const allTurns = session.rounds.flatMap((r2) => r2.turns);
  const scenarios = session.scenarios;
  if (scenarios.length === 0)
    throw new Error("No scenarios found in forum session \u2014 cannot score");
  const clueMap = new Map;
  for (const clue of rawClues) {
    const v = clue.versions[clue.current - 1] ?? clue.versions[clue.versions.length - 1];
    if (!v)
      continue;
    clueMap.set(clue.id, {
      title: v.title,
      clue_type: v.clue_type,
      credibility: v.source_credibility.score,
      bias_flags: v.source_credibility.bias_flags,
      summary: v.bias_corrected_summary
    });
  }
  onProgress?.("Scorer: evidence map built");
  log.expert(`Scorer: ${scenarios.length} scenarios, ${allTurns.length} turns, ${scratchpads.length} scratchpads, ${rawClues.length} clues`);
  const evidenceMap = buildEvidenceMap(scenarios, allTurns, scratchpads, parties, clueMap);
  log.expert(`Scorer: evidence map ready \u2014 power projections: ${evidenceMap.map((e) => `${e.scenario_id}=${Math.round(e.net_power_projection)}`).join(", ")}`);
  emitThink(topicId, "\uD83D\uDCCA", "Evidence map complete", `${scenarios.length} scenarios mapped`);
  emit(topicId, { type: "progress", stage: "expert_council", pct: 0.4, msg: "Scoring scenario probabilities..." });
  onProgress?.("Scorer: running probability scoring");
  const evidenceStr = serializeEvidenceMap(evidenceMap, parties);
  const userPrompt = fitContext([
    { content: `TOPIC: ${topicId}`, priority: 5, label: "topic" },
    { content: `EVIDENCE PACKAGE:
${evidenceStr}`, priority: 10, label: "evidence" },
    { content: `
Score all ${scenarios.length} scenarios. Probabilities must sum to exactly 1.0.`, priority: 10, label: "instruction" }
  ], 80000);
  const budget = budgetOutput(effectiveModel, SCORER_PROMPT + userPrompt, { min: 4000, max: 12000 });
  let verdict = null;
  for (let attempt = 0;attempt < 3; attempt++) {
    let raw;
    if (scorerConfig.tools.length > 0) {
      raw = await runAgenticLoop({
        model: effectiveModel,
        messages: [
          { role: "system", content: SCORER_PROMPT },
          { role: "user", content: userPrompt }
        ],
        tools: scorerConfig.tools,
        topicId,
        stage: "expert",
        temperature: 0.2,
        max_tokens: budget
      });
    } else {
      raw = await chatCompletionText({
        model: effectiveModel,
        messages: [
          { role: "system", content: SCORER_PROMPT },
          { role: "user", content: userPrompt }
        ],
        temperature: 0.2,
        max_tokens: budget
      });
    }
    try {
      const match = raw.match(/\{[\s\S]+\}/);
      if (!match)
        throw new Error("No JSON object found");
      const parsed = JSON.parse(match[0]);
      if (!Array.isArray(parsed.scenarios_ranked))
        throw new Error("Missing scenarios_ranked array");
      verdict = parsed;
      break;
    } catch (e) {
      log.error("SCORER", `Attempt ${attempt + 1} failed`, e);
    }
  }
  if (!verdict)
    throw new Error("Scenario scorer failed after 3 attempts");
  const rawTotal = verdict.scenarios_ranked.reduce((s, r2) => s + r2.probability, 0);
  if (Math.abs(rawTotal - 1) > 0.01) {
    const scale = 1 / rawTotal;
    for (const r2 of verdict.scenarios_ranked) {
      r2.probability = Math.round(r2.probability * scale * 1000) / 1000;
    }
    const adjustedTotal = verdict.scenarios_ranked.reduce((s, r2) => s + r2.probability, 0);
    verdict.scenarios_ranked[verdict.scenarios_ranked.length - 1].probability = Math.round((verdict.scenarios_ranked[verdict.scenarios_ranked.length - 1].probability + (1 - adjustedTotal)) * 1000) / 1000;
  }
  verdict.scenarios_ranked.sort((a12, b) => b.probability - a12.probability);
  const finalVerdict = {
    synthesized_at: new Date().toISOString(),
    scenarios_ranked: verdict.scenarios_ranked,
    final_assessment: verdict.final_assessment,
    confidence_note: verdict.confidence_note,
    weight_challenge_decisions: []
  };
  let effectiveVersion = version ?? 1;
  if (!version) {
    try {
      const topic = dbGetTopic(topicId);
      if (topic)
        effectiveVersion = Math.max(effectiveVersion, topic.current_version || 0);
    } catch {}
    const vMatch = runId.match(/v(\d+)/);
    if (vMatch)
      effectiveVersion = parseInt(vMatch[1]);
  }
  const councilOutput = {
    version: effectiveVersion,
    verdict_id: `verdict-v${effectiveVersion}`,
    experts: [],
    deliberations: [],
    final_verdict: finalVerdict
  };
  dbSaveExpertCouncil(topicId, councilOutput);
  await writeArtifact(topicId, runId, "verdict_synthesis", finalVerdict);
  const rankedStr = finalVerdict.scenarios_ranked.map((s) => `${(s.title ?? s.scenario_id).slice(0, 30)}=${Math.round(s.probability * 100)}%`).join(", ");
  log.expert(`Scorer complete: ${rankedStr}`);
  emitThink(topicId, "\u2705", "Scenario scoring complete", rankedStr);
  emit(topicId, {
    type: "verdict_content",
    headline: finalVerdict.final_assessment.slice(0, 200),
    scenarios: finalVerdict.scenarios_ranked.map((s) => ({ title: s.title ?? s.scenario_id, probability: s.probability })),
    final_assessment: finalVerdict.final_assessment,
    confidence_note: finalVerdict.confidence_note
  });
  emit(topicId, { type: "stage_complete", stage: "expert_council" });
  onProgress?.("Scorer: complete");
  return councilOutput;
}

// src/pipeline/checkpointManager.ts
import { join as join6 } from "path";
import { mkdir as mkdir2 } from "fs/promises";
function getDataDir4() {
  return process.env.DATA_DIR || "/home/nima/dana/data";
}
function checkpointPath(topicId, runId) {
  return join6(getDataDir4(), "topics", topicId, "logs", `run-${runId}`, "checkpoint.json");
}
async function writeCheckpoint(topicId, runId, update3) {
  const path = checkpointPath(topicId, runId);
  const dir = join6(getDataDir4(), "topics", topicId, "logs", `run-${runId}`);
  await mkdir2(dir, { recursive: true });
  const file2 = Bun.file(path);
  const existing = await file2.exists() ? await file2.json() : null;
  const checkpoint = {
    run_id: runId,
    topic_id: topicId,
    stage: update3.stage ?? existing?.stage ?? "discovery",
    step: update3.step ?? existing?.step ?? 0,
    completed_turn_ids: update3.completed_turn_ids ?? existing?.completed_turn_ids ?? [],
    created_at: existing?.created_at ?? new Date().toISOString(),
    updated_at: new Date().toISOString()
  };
  await Bun.write(path, JSON.stringify(checkpoint, null, 2));
  return checkpoint;
}
async function readCheckpoint(topicId, runId) {
  const file2 = Bun.file(checkpointPath(topicId, runId));
  if (!await file2.exists())
    return null;
  return file2.json();
}
function isStageComplete(checkpoint, stage) {
  if (!checkpoint)
    return false;
  const order = ["discovery", "enrichment", "weight", "forum_prep", "forum", "expert_council", "verdict"];
  return order.indexOf(checkpoint.stage) > order.indexOf(stage);
}

// src/pipeline/initialPipeline.ts
init_stream2();
init_topicManager();
async function updateTopicStatus(topicId, status2) {
  await updateTopic(topicId, { status: status2 });
}
async function loadTopic(topicId) {
  return getTopic(topicId);
}
async function runInitialPipeline(topicId, runId) {
  const topic = await loadTopic(topicId);
  const v = await allocateVersion(topicId, { forkFrom: null, forkStage: null });
  runId = runId ?? `run-v${v}`;
  const checkpoint = await readCheckpoint(topicId, runId);
  const progress = makeProgressEmitter(topicId, "pipeline");
  const sessionId = `forum-session-v${v}`;
  try {
    log.separator();
    log.pipeline(`Starting initial pipeline for "${topic.title}"`, `run=${runId}, version=${v}`);
    log.pipeline(`Models: enrichment=${topic.models.enrichment} forum=${topic.models.forum_reasoning} scorer=${topic.models.expert_council}`);
    log.separator();
    const pipelineStart = Date.now();
    if (!isStageComplete(checkpoint, "discovery")) {
      await updateTopicStatus(topicId, "discovery");
      log.discovery("Stage 1/5: DISCOVERY starting");
      emit(topicId, { type: "progress", stage: "discovery", pct: 0, msg: "Starting discovery..." });
      await runDiscoveryAgent(topicId, topic.title, topic.description, topic.models.enrichment, runId, (msg) => emit(topicId, { type: "progress", stage: "discovery", pct: 0.5, msg }));
      await writeCheckpoint(topicId, runId, { stage: "enrichment", step: 0 });
      log.discovery("Stage 1/5: DISCOVERY complete");
      emit(topicId, { type: "stage_complete", stage: "discovery" });
    } else {
      log.discovery("Stage 1/5: DISCOVERY skipped (checkpoint)");
    }
    if (!isStageComplete(checkpoint, "enrichment")) {
      await updateTopicStatus(topicId, "enrichment");
      log.enrichment("Stage 2/5: ENRICHMENT starting");
      emit(topicId, { type: "progress", stage: "enrichment", pct: 0, msg: "Starting enrichment..." });
      await runEnrichmentAgent(topicId, topic.title, topic.description, { enrichment: topic.models.enrichment, extraction: topic.models.extraction }, runId, (msg) => emit(topicId, { type: "progress", stage: "enrichment", pct: 0.5, msg }));
      await writeCheckpoint(topicId, runId, { stage: "weight", step: 0 });
      log.enrichment("Stage 2/5: ENRICHMENT complete");
      emit(topicId, { type: "stage_complete", stage: "enrichment" });
    } else {
      log.enrichment("Stage 2/5: ENRICHMENT skipped (checkpoint)");
    }
    if (!isStageComplete(checkpoint, "forum_prep") && !isStageComplete(checkpoint, "weight")) {
      log.weight("Stage 3/5: FORUM PREP starting");
      emit(topicId, { type: "progress", stage: "forum_prep", pct: 0, msg: "Generating forum representatives..." });
      await runForumPrep(topicId, topic.title, topic.models.enrichment, runId, (msg) => emit(topicId, { type: "progress", stage: "forum_prep", pct: 0.5, msg }));
      await writeCheckpoint(topicId, runId, { stage: "forum", step: 0 });
      log.weight("Stage 3/5: FORUM PREP complete");
      emit(topicId, { type: "stage_complete", stage: "forum_prep" });
    } else {
      log.weight("Stage 3/5: FORUM PREP skipped (checkpoint)");
    }
    if (!isStageComplete(checkpoint, "forum")) {
      await updateTopicStatus(topicId, "forum");
      log.forum("Stage 4/5: FORUM starting");
      emit(topicId, { type: "progress", stage: "forum", pct: 0, msg: "Starting forum..." });
      await runForumOrchestrator(topicId, runId, sessionId, topic.models.forum_reasoning, null, (msg) => emit(topicId, { type: "progress", stage: "forum", pct: 0.5, msg }), v);
      await setVersionSessionId(topicId, v, sessionId);
      await writeCheckpoint(topicId, runId, { stage: "expert_council", step: 0 });
      log.forum("Stage 4/5: FORUM complete");
    } else {
      log.forum("Stage 4/5: FORUM skipped (checkpoint)");
    }
    await updateTopicStatus(topicId, "expert_council");
    log.expert("Stage 5/5: SCENARIO SCORER starting");
    emit(topicId, { type: "progress", stage: "expert_council", pct: 0, msg: "Scoring scenarios..." });
    const councilOutput = await runScenarioScorer(topicId, runId, sessionId, topic.models.expert_council, (msg) => emit(topicId, { type: "progress", stage: "expert_council", pct: 0.5, msg }), v);
    await finalizeVersion(topicId, v, {
      forum_session_id: sessionId,
      verdict_id: councilOutput.verdict_id
    });
    emit(topicId, { type: "stage_complete", stage: "verdict" });
    const totalElapsed = Math.round((Date.now() - pipelineStart) / 1000);
    log.separator();
    log.pipeline(`Pipeline COMPLETE in ${totalElapsed}s`, `run=${runId}, version=${v}`);
    log.separator();
    return { run_id: runId, status: "complete" };
  } catch (e) {
    log.error("PIPELINE", "Pipeline FAILED", e);
    emit(topicId, { type: "error", message: String(e) });
    return { run_id: runId, status: `error: ${e}` };
  }
}

