// src/tools/internal/getClue.ts
init_clues();
async function getClue(topicId, clueId, version) {
  const entry = dbGetClueVersion(topicId, clueId, version);
  if (!entry)
    throw new Error(`Clue ${clueId} not found for topic ${topicId}`);
  return { ...entry, bias_flags: entry.source_credibility.bias_flags };
}
async function getClueIndex(topicId) {
  return dbGetClueIndex(topicId);
}

// src/agents/contextBuilder.ts
init_topics();
function getTopicVersion(topicId) {
  return dbGetTopic(topicId)?.current_version ?? 0;
}
function getForumSummary(topicId) {
  const states = dbGetAllStates(topicId);
  if (!states.length)
    return;
  const latest = states[states.length - 1];
  if (!latest.forum_session_id)
    return;
  const session = dbGetForumSession(topicId, latest.forum_session_id);
  if (!session?.scenario_summary?.scenarios?.length)
    return;
  const titles = session.scenario_summary.scenarios.map((s, i) => `${i + 1}. ${s.title}`).join("; ");
  return `Forum produced ${session.scenario_summary.scenarios.length} scenarios: ${titles}`;
}
function getVerdictSummary(topicId) {
  const council = dbGetLatestExpertCouncil(topicId);
  if (!council?.final_verdict?.final_assessment)
    return;
  return council.final_verdict.final_assessment.slice(0, 300);
}
async function buildAgentContext(agentType, topicId) {
  const [party_index, clue_index] = await Promise.all([
    getPartyIndex(topicId),
    getClueIndex(topicId)
  ]);
  const snapshot = {
    current_version: getTopicVersion(topicId),
    party_index,
    clue_index
  };
  if (agentType === "expert" || agentType === "verdict") {
    snapshot.forum_summary = getForumSummary(topicId);
  }
  if (agentType === "delta") {
    snapshot.prior_verdict_summary = getVerdictSummary(topicId);
  }
  return snapshot;
}
function serializeContext(snapshot) {
  const lines = [
    `Version: ${snapshot.current_version}`,
    `Parties (${snapshot.party_index.length}): ${snapshot.party_index.map((p) => `${p.name} [w=${p.weight}]`).join(", ")}`,
    `Clues (${snapshot.clue_index.length}): ${snapshot.clue_index.map((c) => `[${c.id}] ${c.title} (${c.timeline_date})`).join(" | ")}`
  ];
  if (snapshot.forum_summary)
    lines.push(`Forum summary: ${snapshot.forum_summary}`);
  if (snapshot.prior_verdict_summary)
    lines.push(`Prior verdict: ${snapshot.prior_verdict_summary}`);
  return lines.join(`
`);
}

// src/agents/DeltaRepresentativeAgent.ts
async function runDeltaRepresentativeAgent(topicId, runId, partyId, priorSessionId, deltaContext, model, onProgress) {
  const deltaConfig = await resolvePrompt("delta-representative/system");
  const effectiveModel = deltaConfig.model ?? model;
  const DELTA_SYSTEM = deltaConfig.content;
  onProgress?.(`Delta rep ${partyId}: assessing new evidence`);
  const ctx = await buildAgentContext("delta", topicId);
  const contextStr = serializeContext(ctx);
  const party = await getPartyProfile(topicId, partyId);
  const priorTurns = await getPriorTurns(topicId, priorSessionId, { party_id: partyId });
  const priorStatementsStr = priorTurns.length > 0 ? priorTurns.map((t2) => `[R${t2.round}]: ${t2.statement.slice(0, 400)}`).join(`

`) : "No prior statements found.";
  const clueDetails = [];
  for (const cId of [...deltaContext.new_clues, ...deltaContext.updated_clues]) {
    try {
      const clue = await getClue(topicId, cId);
      clueDetails.push(`[${cId}] ${clue.title}: ${clue.bias_corrected_summary}`);
    } catch {}
  }
  const reps = dbGetRepresentatives(topicId);
  const rep = reps.find((r2) => r2.party_id === partyId);
  const persona = rep?.persona_prompt ?? `You represent ${party.name}.`;
  const userPrompt = `${persona}

CONTEXT:
${contextStr}

YOUR PARTY: ${party.name}
AGENDA: ${party.agenda}

WHAT CHANGED:
${deltaContext.change_narrative}

NEW/UPDATED CLUES:
${clueDetails.join(`
`)}

YOUR PRIOR STATEMENTS:
${priorStatementsStr}

Produce your position update as JSON.`;
  let deltaTurn = null;
  for (let attempt = 0;attempt < 3; attempt++) {
    let raw;
    if (deltaConfig.tools.length > 0) {
      raw = await runAgenticLoop({
        model: effectiveModel,
        messages: [
          { role: "system", content: DELTA_SYSTEM },
          { role: "user", content: userPrompt }
        ],
        tools: deltaConfig.tools,
        topicId,
        stage: "delta",
        temperature: 0.4,
        max_tokens: 800
      });
    } else {
      raw = await chatCompletionText({
        model: effectiveModel,
        messages: [
          { role: "system", content: DELTA_SYSTEM },
          { role: "user", content: userPrompt }
        ],
        temperature: 0.4,
        max_tokens: 800
      });
    }
    try {
      const match = raw.match(/\{[\s\S]+\}/);
      if (!match)
        throw new Error("No JSON found");
      deltaTurn = JSON.parse(match[0]);
      break;
    } catch (e) {
      console.warn(`Delta rep ${partyId} attempt ${attempt + 1} failed:`, e);
    }
  }
  if (!deltaTurn)
    throw new Error(`Delta rep ${partyId} failed after 3 attempts`);
  const result = {
    id: `delta-turn-${partyId}`,
    representative_id: `rep-${partyId}`,
    party_name: party.name,
    type: "position_update",
    prior_position_summary: deltaTurn.prior_position_summary,
    updated_position: deltaTurn.updated_position,
    position_delta: deltaTurn.position_delta,
    clues_cited: deltaTurn.clues_cited || [],
    timestamp: new Date().toISOString(),
    word_count: deltaTurn.updated_position?.split(/\s+/).length ?? 0
  };
  await writeArtifact(topicId, runId, `delta_representative_${partyId}`, result);
  onProgress?.(`Delta rep ${partyId}: ${result.position_delta}`);
  return result;
}

// src/pipeline/deltaPipeline.ts
init_proxyClient();
init_agenticLoop();
init_promptLoader();
init_stream2();
init_topicManager();
async function loadTopic2(topicId) {
  return getTopic(topicId);
}
async function updateTopicStatus2(topicId, status2) {
  await updateTopic(topicId, { status: status2 });
}
async function runDeltaPipeline(topicId, runId) {
  runId = runId ?? `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 6)}`;
  const topic = await loadTopic2(topicId);
  try {
    emit(topicId, { type: "progress", stage: "delta", pct: 0, msg: "Computing clue delta..." });
    const latestState = await getLatestVersion(topicId);
    if (!latestState)
      throw new Error("No prior state found");
    const delta3 = await computeDelta(topicId);
    if (!delta3)
      throw new Error("No changes detected");
    const deltaContext = {
      new_clues: delta3.new_clues,
      updated_clues: delta3.updated_clues,
      affected_parties: delta3.affected_parties,
      change_narrative: delta3.key_change
    };
    const priorSessionId = latestState.forum_session_id ?? "forum-session-v1";
    const newVersion = latestState.version + 1;
    const newSessionId = `forum-session-v${newVersion}`;
    await updateTopicStatus2(topicId, "forum");
    emit(topicId, { type: "progress", stage: "forum", pct: 0, msg: "Running delta forum..." });
    const reps = dbGetRepresentatives(topicId);
    const deltaTurns = [];
    for (const rep of reps) {
      const turn = await runDeltaRepresentativeAgent(topicId, runId, rep.party_id, priorSessionId, deltaContext, topic.models.delta_updates, (msg) => emit(topicId, { type: "progress", stage: "forum", pct: 0.5, msg }));
      deltaTurns.push(turn);
      emit(topicId, { type: "forum_turn", turn });
    }
    emit(topicId, { type: "progress", stage: "forum", pct: 0.8, msg: "Synthesizing scenario updates..." });
    const scenarioUpdatePrompt = `Given these position updates from representatives, determine how each scenario is affected.

DELTA CONTEXT: ${deltaContext.change_narrative}

POSITION UPDATES:
${deltaTurns.map((t2) => `${t2.party_name}: ${t2.position_delta} \u2014 ${t2.updated_position.slice(0, 300)}`).join(`

`)}

Output JSON array:
[{ "scenario_id": "<id>", "update_type": "strengthened" | "weakened" | "unchanged" | "new", "reason": "<brief reason>" }]`;
    const impactConfig = await resolvePrompt("forum/delta-scenario-impact");
    const impactModel = impactConfig.model ?? topic.models.delta_updates;
    let scenarioUpdates = [];
    try {
      let raw;
      if (impactConfig.tools.length > 0) {
        raw = await runAgenticLoop({
          model: impactModel,
          messages: [
            { role: "system", content: impactConfig.content },
            { role: "user", content: scenarioUpdatePrompt }
          ],
          tools: impactConfig.tools,
          topicId,
          stage: "delta",
          temperature: 0.3,
          max_tokens: 1000
        });
      } else {
        raw = await chatCompletionText({
          model: impactModel,
          messages: [
            { role: "system", content: impactConfig.content },
            { role: "user", content: scenarioUpdatePrompt }
          ],
          temperature: 0.3,
          max_tokens: 1000
        });
      }
      const match = raw.match(/\[[\s\S]+\]/);
      if (match)
        scenarioUpdates = JSON.parse(match[0]);
    } catch (e) {
      console.warn("Scenario update synthesis failed:", e);
    }
    const deltaSession = {
      session_id: newSessionId,
      version: newVersion,
      type: "delta",
      status: "complete",
      started_at: new Date().toISOString(),
      completed_at: new Date().toISOString(),
      rounds: [{
        round: 1,
        type: "position_updates",
        turns: deltaTurns.map((t2) => ({
          id: t2.id,
          representative_id: t2.representative_id,
          party_name: t2.party_name,
          statement: `PRIOR: ${t2.prior_position_summary}

UPDATED: ${t2.updated_position}

DELTA: ${t2.position_delta}`,
          clues_cited: t2.clues_cited,
          timestamp: t2.timestamp,
          round: 1,
          type: "position_update",
          word_count: t2.word_count
        }))
      }],
      scenarios: [],
      scenario_summary: {
        scenarios: [],
        contested_clues: [],
        uncontested_clues: []
      }
    };
    await writeForumSession(topicId, deltaSession);
    await writeArtifact(topicId, runId, "delta_forum_orchestrator", { scenario_updates: scenarioUpdates });
    emit(topicId, { type: "stage_complete", stage: "forum" });
    await updateTopicStatus2(topicId, "expert_council");
    emit(topicId, { type: "progress", stage: "expert_council", pct: 0, msg: "Scoring updated scenarios..." });
    const councilOutput = await runScenarioScorer(topicId, runId, priorSessionId, topic.models.delta_updates, (msg) => emit(topicId, { type: "progress", stage: "expert_council", pct: 0.5, msg }));
    await createVersion(topicId, {
      label: `Delta update: ${deltaContext.change_narrative.slice(0, 80)}`,
      trigger: "user_manual",
      forum_session_id: newSessionId,
      verdict_id: `verdict-v${newVersion}`,
      delta_from: latestState.version,
      delta_summary: delta3
    });
    await updateTopicStatus2(topicId, "complete");
    emit(topicId, { type: "stage_complete", stage: "verdict" });
    return { run_id: runId, status: "complete" };
  } catch (e) {
    console.error("Delta pipeline failed:", e);
    emit(topicId, { type: "error", message: String(e) });
    return { run_id: runId, status: `error: ${e}` };
  }
}

