// src/routes/providers.ts
init_dist2();
init_proxyClient();
import { readdirSync as readdirSync2, rmSync, existsSync as existsSync2, mkdirSync as mkdirSync4, readFileSync as readFileSync3 } from "fs";
import { join as join9 } from "path";
import { spawn } from "child_process";
var credentialsDir = () => join9(process.env.DATA_DIR || "/home/nima/dana/data", ".cli-proxy-api");
var loginTimeoutMs = Number(process.env.PROVIDER_LOGIN_TIMEOUT_MS || 120000);
var activeLogins = new Map;
function ensureCredentialsDir() {
  mkdirSync4(credentialsDir(), { recursive: true });
}
function providerLabel(provider) {
  return provider === "claude" ? "Anthropic" : provider[0].toUpperCase() + provider.slice(1);
}
function scanProviderCredentials() {
  const dir = credentialsDir();
  if (!existsSync2(dir))
    return [];
  return readdirSync2(dir).filter((name) => name.endsWith(".json") || name.endsWith(".yaml") || name.endsWith(".yml") || name.endsWith(".token"));
}
function normalizeProvider(provider) {
  return provider.toLowerCase().trim();
}
function loginFlagForProvider(provider) {
  if (provider === "openai")
    return "codex";
  if (provider === "gemini")
    return "login";
  return provider;
}
function providerFromFile(name) {
  const normalized = name.replace(/\.(json|yaml|yml|token)$/i, "");
  const base = normalized.replace(/^(credentials-|auth-|token-)/, "");
  if (base.startsWith("claude-"))
    return "claude";
  if (base.startsWith("codex-") || base.startsWith("openai-") || base.startsWith("gpt-"))
    return "openai";
  if (base.startsWith("gemini-") || base.startsWith("google-") || base === "google")
    return "gemini";
  if (base.startsWith("qwen-"))
    return "qwen";
  if (base.startsWith("kimi-"))
    return "kimi";
  if (base.startsWith("iflow-"))
    return "iflow";
  if (base.startsWith("antigravity-"))
    return "antigravity";
  return base.split("-")[0];
}
var providersRouter = new Elysia({ prefix: "/api/providers" }).get("/", async () => {
  const files = scanProviderCredentials();
  const connected = files.map((file2) => {
    const provider = providerFromFile(file2);
    let account = null;
    try {
      const raw = readFileSync3(join9(credentialsDir(), file2), "utf8");
      const parsed = raw.trim().startsWith("{") ? JSON.parse(raw) : null;
      account = parsed?.email || parsed?.account || parsed?.username || parsed?.name || null;
    } catch {}
    return { provider, label: providerLabel(provider), status: "connected", account, credential_file: file2 };
  });
  return { providers: connected };
}).post("/login", async ({ body, set: set2 }) => {
  if (!await isProxyAvailable()) {
    set2.status = 503;
    return { error: "CLIProxyAPI unavailable" };
  }
  const provider = normalizeProvider(body.provider);
  ensureCredentialsDir();
  const existing = activeLogins.get(provider);
  if (existing?.proc) {
    try {
      existing.proc.kill();
    } catch {}
  }
  const configFlag = process.env.CLIPROXY_CONFIG ? `-config ${process.env.CLIPROXY_CONFIG}` : "-config /tmp/cli-proxy-config.yaml";
  const callbackPort = process.env.OAUTH_CALLBACK_PORT || "54545";
  const loginFlag = loginFlagForProvider(provider);
  const callbackArg = loginFlag === "codex" ? "" : `-oauth-callback-port ${callbackPort} `;
  const loginArg = loginFlag === "login" ? "-login" : `-${loginFlag}-login`;
  const command = `CLIProxyAPI ${configFlag} ${callbackArg}${loginArg} -no-browser`;
  const proc = spawn(command, { shell: true, env: process.env });
  const state = { startedAt: Date.now(), done: false, oauthUrl: undefined, error: undefined, proc };
  activeLogins.set(provider, state);
  proc.stdout.on("data", (chunk) => {
    const text3 = String(chunk);
    const match = text3.match(/https?:\/\/\S+/);
    if (match && !state.oauthUrl)
      state.oauthUrl = match[0];
  });
  proc.stderr.on("data", (chunk) => {
    const text3 = String(chunk);
    if (!state.error)
      state.error = text3.trim();
  });
  proc.on("exit", (code) => {
    state.done = code === 0;
  });
  return { provider, oauth_url: state.oauthUrl ?? null, status: "started" };
}, { body: t.Object({ provider: t.String() }) }).get("/login/status", async ({ query: query2 }) => {
  const provider = normalizeProvider(query2.provider);
  const state = activeLogins.get(provider);
  const credential = scanProviderCredentials().find((file2) => providerFromFile(file2) === provider);
  if (credential) {
    return { provider, connected: true, timeout: false };
  }
  if (!state)
    return { provider, connected: false, timeout: false };
  const timedOut = Date.now() - state.startedAt > loginTimeoutMs;
  if (timedOut)
    return { provider, connected: false, timeout: true };
  return { provider, connected: state.done, timeout: false, oauth_url: state.oauthUrl ?? null, error: state.error ?? null };
}).delete("/:provider", async ({ params, set: set2 }) => {
  const provider = normalizeProvider(params.provider);
  ensureCredentialsDir();
  const files = scanProviderCredentials().filter((file2) => providerFromFile(file2) === provider);
  for (const file2 of files)
    rmSync(join9(credentialsDir(), file2), { force: true });
  return { provider, removed: files.length };
}).get("/models", async () => {
  const models = await fetchAvailableModels();
  const grouped = new Map;
  for (const model of models) {
    const rawProvider = (model.owned_by || model.id.split("/")[0] || "unknown").toLowerCase();
    const provider = rawProvider === "anthropic" ? "claude" : rawProvider === "google" ? "gemini" : rawProvider;
    if (!grouped.has(provider))
      grouped.set(provider, []);
    grouped.get(provider).push(model.id);
  }
  return { providers: Array.from(grouped.entries()).map(([provider, models2]) => ({ provider, models: models2 })) };
}).get("/health", async () => {
  const proxyUp = await isProxyAvailable();
  const credentials = scanProviderCredentials();
  const connectedProviders = [...new Set(credentials.map((f) => providerFromFile(f)))];
  let modelCount = 0;
  if (proxyUp) {
    const models = await fetchAvailableModels();
    modelCount = models.length;
  }
  return {
    proxy_online: proxyUp,
    connected_providers: connectedProviders,
    model_count: modelCount,
    credential_files: credentials.length
  };
});

