var app = new Elysia().use(cors()).use(swagger({ path: "/docs" })).use(topicsRouter).use(streamRouter).use(cluesRouter).use(partiesRouter).use(forumRouter).use(pipelineRouter).use(expertCouncilRouter).use(settingsRouter).use(promptsRouter).use(providersRouter).get("/health", () => ({ status: "ok" })).get("/api/health", () => ({ status: "ok" })).get("/api/models", async () => {
  return fetchAvailableModels();
}).get("/api/models/catalog", async () => {
  return getModelCatalog();
}).get("/assets/*", ({ path }) => {
  const filePath = join10(DIST_DIR, path.replace(/^\/assets\//, "assets/"));
  return serveStatic(filePath);
}).get("/favicon.svg", () => serveStatic(join10(DIST_DIR, "favicon.svg"))).get("/icons.svg", () => serveStatic(join10(DIST_DIR, "icons.svg"))).get("/*", ({ path }) => {
  if (path.startsWith("/api/"))
    return new Response("Not found", { status: 404 });
  return serveStatic(join10(DIST_DIR, "index.html"));
}).listen(Number(process.env.PORT) || 3000);
console.log(`\x1B[1m\x1B[36mDana\x1B[0m backend running at \x1B[36mhttp://localhost:${app.server?.port}\x1B[0m`);
